class Price(object):
    """
    Simple price class that encapsulates a price and its tax information

    Attributes:
        incl_tax (Decimal): Price including taxes
        excl_tax (Decimal): Price excluding taxes
        tax (Decimal): Tax amount
        is_tax_known (bool): Whether tax is known
        currency (str): 3 character currency code
    """

    def __init__(self, currency, excl_tax, incl_tax=None, tax=None, tax_code=None):
        self.currency = currency
        self.excl_tax = excl_tax
        self.tax_code = tax_code
        if incl_tax is not None:
            self.incl_tax = incl_tax
            self.is_tax_known = True
        elif tax is not None:
            self.incl_tax = excl_tax + tax
            self.is_tax_known = True
        else:
            self.incl_tax = None
            self.is_tax_known = False

    def _get_tax(self):
        return self.incl_tax - self.excl_tax

    def _set_tax(self, value):
        self.incl_tax = self.excl_tax + value
        self.is_tax_known = True
    tax = property(_get_tax, _set_tax)

    def __repr__(self):
        if self.is_tax_known:
            return '%s(currency=%r, excl_tax=%r, incl_tax=%r, tax=%r)' % (self.__class__.__name__, self.currency, self.excl_tax, self.incl_tax, self.tax)
        return '%s(currency=%r, excl_tax=%r)' % (self.__class__.__name__, self.currency, self.excl_tax)

    def __eq__(self, other):
        """
        Two price objects are equal if currency, price.excl_tax and tax match.
        """
        return self.currency == other.currency and self.excl_tax == other.excl_tax and (self.incl_tax == other.incl_tax)

    def __add__(self, other):
        if self.currency != other.currency:
            raise ValueError('Cannot add prices with different currencies.')
        return Price(currency=self.currency, incl_tax=self.incl_tax + other.incl_tax, excl_tax=self.excl_tax + other.excl_tax, tax_code=self.tax_code)

    def __radd__(self, other):
        if other == 0:
            return self
        else:
            return self.__add__(other)

class AbstractThumbnailer(object):

    def generate_thumbnail(self, source, **opts):
        raise NotImplementedError

    def delete_thumbnails(self, source):
        raise NotImplementedError

class SorlThumbnail(AbstractThumbnailer):

    def __init__(self):
        if not apps.is_installed('sorl.thumbnail'):
            raise ValueError('"sorl.thumbnail" is not listed in "INSTALLED_APPS".')

    def generate_thumbnail(self, source, **opts):
        from sorl.thumbnail import get_thumbnail
        size = opts.pop('size')
        width, height = size.split('x')
        size = size if height else width
        return get_thumbnail(source, size, **opts)

    def delete_thumbnails(self, source):
        from sorl.thumbnail import delete
        from sorl.thumbnail.helpers import ThumbnailError
        try:
            delete(source)
        except ThumbnailError:
            pass

class EasyThumbnails(AbstractThumbnailer):

    def __init__(self):
        if not apps.is_installed('easy_thumbnails'):
            raise ValueError('"easy_thumbnails" is not listed in "INSTALLED_APPS".')

    def generate_thumbnail(self, source, **opts):
        from easy_thumbnails.files import get_thumbnailer as get_easy_thumbnailer
        width, height = opts['size'].split('x')
        width = width or 0
        height = height or 0
        opts['size'] = (width, height)
        return get_easy_thumbnailer(source).get_thumbnail(opts)

    def delete_thumbnails(self, source):
        from easy_thumbnails.files import get_thumbnailer as get_easy_thumbnailer
        get_easy_thumbnailer(source).delete(save=False)

class ExtendedURLValidator(validators.URLValidator):

    def __init__(self, *args, **kwargs):
        self.is_local_url = False
        super().__init__(*args, **kwargs)

    def __call__(self, value):
        try:
            super().__call__(value)
        except ValidationError:
            if value:
                self.validate_local_url(value)
            else:
                raise

    def _validate_url(self, value):
        try:
            resolve(value)
        except Http404:
            FlatPage = get_model('flatpages', 'FlatPage')
            if FlatPage is not None:
                try:
                    FlatPage.objects.get(url=value)
                except FlatPage.DoesNotExist:
                    self.is_local_url = True
                else:
                    return
            raise ValidationError(_('The URL "%s" does not exist') % value)
        else:
            self.is_local_url = True

    def validate_local_url(self, value):
        value = self.clean_url(value)
        urlconf = get_urlconf()
        i18n_patterns_used, _ = is_language_prefix_patterns_used(urlconf)
        redefined_language = None
        if i18n_patterns_used:
            language = get_language_from_path(value)
            current_language = get_language()
            if language != current_language:
                redefined_language = language
        if redefined_language:
            with override(redefined_language):
                self._validate_url(value)
        else:
            self._validate_url(value)

    def clean_url(self, value):
        """
        Ensure url has a preceding slash and no query string
        """
        if value != '/':
            value = '/' + value.lstrip('/')
        q_index = value.find('?')
        if q_index > 0:
            value = value[:q_index]
        return value

class ExtendedURLField(fields.URLField):
    """
    Custom field similar to URLField type field, however also accepting and
    validating local relative URLs, ie. '/product/'
    """
    default_validators = []
    widget = TextInput

    def __init__(self, *args, **kwargs):
        super(fields.URLField, self).__init__(*args, **kwargs)
        self.validators.append(validators.ExtendedURLValidator())

    def to_python(self, value):
        if value and value.startswith('/'):
            return value
        return super().to_python(value)

class PhoneNumberMixin(object):
    """Validation mixin for forms with a phone numbers, and optionally a country.

    It tries to validate the phone numbers, and on failure tries to validate
    them using a hint (the country provided), and treating it as a local number.

    Specify which fields to treat as phone numbers by specifying them in
    `phone_number_fields`, a dictionary of fields names and default kwargs
    for instantiation of the field.
    """
    country = None
    region_code = None
    phone_number_fields = {'phone_number': {'required': False, 'help_text': '', 'max_length': 32, 'label': _('Phone number')}}

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        for field_name, field_kwargs in self.phone_number_fields.items():
            for key in field_kwargs:
                try:
                    field_kwargs[key] = getattr(self.fields[field_name], key)
                except (KeyError, AttributeError):
                    pass
            self.fields[field_name] = forms.CharField(**field_kwargs)

    def get_country(self):
        if hasattr(self, 'cleaned_data') and 'country' in self.cleaned_data:
            return self.cleaned_data['country']
        elif 'country' not in self.fields and hasattr(self.instance, 'country'):
            return self.instance.country

    def set_country_and_region_code(self):
        self.country = self.get_country()
        if self.country:
            self.region_code = self.country.iso_3166_1_a2

    def clean_phone_number_field(self, field_name):
        number = self.cleaned_data.get(field_name)
        if number in validators.EMPTY_VALUES:
            return ''
        try:
            phone_number = PhoneNumber.from_string(number)
        except phonenumbers.NumberParseException:
            if not self.region_code:
                self.add_error(field_name, _('This is not a valid international phone format.'))
                return number
            try:
                phone_number = PhoneNumber.from_string(number, region=self.region_code)
                if not phone_number.is_valid():
                    self.add_error(field_name, _('This is not a valid local phone format for %s.') % self.country)
            except phonenumbers.NumberParseException:
                self.add_error(field_name, _('This is not a valid local or international phone format.'))
                return number
        return phone_number

    def clean(self):
        self.set_country_and_region_code()
        cleaned_data = super().clean()
        for field_name in self.phone_number_fields:
            cleaned_data[field_name] = self.clean_phone_number_field(field_name)
        return cleaned_data

