    def render(self, context):
        if not feature_hidden(self.feature_name):
            output = self.nodelist.render(context)
            return output
        else:
            return ''

class DynamicImageNode(template.Node):

    def __init__(self, image, params):
        self.image = image
        self.params = {}
        for p in params:
            try:
                bits = p.split('=')
                self.params[bits[0]] = template.Variable(bits[1])
            except IndexError:
                raise template.TemplateSyntaxError("image tag parameters must be of form key=value, you used '%s'" % p)

    def render(self, context):
        if isinstance(self.image, ImageFieldFile):
            path = self.image.name
        else:
            path = self.image
        host = getattr(settings, 'DYNAMIC_MEDIA_URL', None)
        if host:
            params = []
            ext = path[path.rfind('.') + 1:]
            ext_changed = False
            for key, v in self.params.items():
                value = v.resolve(context)
                if key == 'format':
                    ext = value
                    ext_changed = True
                else:
                    params.append('%s-%s' % (key, value))
            if len(params) > 0:
                suffix = '_'.join(params)
                path = '.'.join((path, suffix, ext))
            elif ext_changed:
                if params:
                    path = '.'.join((path, ext))
                else:
                    path = '.'.join((path, 'to', ext))
            return host + path

class ThumbnailNode(template.Node):
    no_resolve = {'True': True, 'False': False, 'None': None}

    def __init__(self, parser, token):
        args = token.split_contents()
        self.source_var = parser.compile_filter(args[1])
        self.size_var = parser.compile_filter(args[2])
        is_context_variable = args[-2] == 'as'
        if is_context_variable:
            self.context_name = args[-1]
            args = args[3:-2]
        else:
            self.context_name = None
            args = args[3:]
        self.options = []
        for arg in args:
            m = kw_pat.match(arg)
            key = smart_str(m.group('key'))
            expr = parser.compile_filter(m.group('value'))
            self.options.append((key, expr))

    def get_thumbnail_options(self, context):
        return {'size': self.size_var.resolve(context)}

    def render(self, context):
        try:
            return self._render(context)
        except Exception as e:
            if getattr(settings, 'OSCAR_THUMBNAIL_DEBUG', settings.DEBUG):
                raise e
            logger.exception(e)
            return ''

    def _render(self, context):
        source = self.source_var.resolve(context)
        options = self.get_thumbnail_options(context)
        for key, expr in self.options:
            value = self.no_resolve.get(str(expr), expr.resolve(context))
            options[key] = value
        thumbnailer = get_thumbnailer()
        thumbnail = thumbnailer.generate_thumbnail(source, **options)
        if self.context_name is None:
            return escape(thumbnail.url)
        else:
            context[self.context_name] = thumbnail
            return ''

class WebTestCase(WebTest):
    is_staff = False
    is_anonymous = False
    is_superuser = False
    username = 'testuser'
    email = 'testuser@buymore.com'
    password = 'somefancypassword'
    permissions = []

    def setUp(self):
        self.user = None
        if not self.is_anonymous:
            self.user = self.create_user(self.username, self.email, self.password)
            self.user.is_staff = self.is_staff
            add_permissions(self.user, self.permissions)
            self.user.save()

    def create_user(self, username=None, email=None, password=None):
        """
        Create a user for use in a test.

        As usernames are optional in newer versions of Django, it only sets it
        if exists.
        """
        kwargs = {'email': email, 'password': password}
        fields = {f.name: f for f in User._meta.get_fields()}
        if 'username' in fields:
            kwargs['username'] = username
        return User.objects.create_user(**kwargs)

    def get(self, url, **kwargs):
        kwargs.setdefault('user', self.user)
        return self.app.get(url, **kwargs)

    def post(self, url, **kwargs):
        kwargs.setdefault('user', self.user)
        return self.app.post(url, **kwargs)

    def assertIsRedirect(self, response, expected_url=None):
        self.assertTrue(response.status_code in (http_client.FOUND, http_client.MOVED_PERMANENTLY))
        if expected_url:
            location = URL.from_string(response['Location'])
            self.assertEqual(expected_url, location.path())

    def assertIsNotRedirect(self, response):
        self.assertIsOk(response)
        self.assertTrue(response.status_code not in (http_client.FOUND, http_client.MOVED_PERMANENTLY))

    def assertRedirectsTo(self, response, url_name, kwargs=None):
        """
        Asserts that a response is a redirect to a given URL name.
        """
        self.assertIsRedirect(response)
        location = response.headers['Location']
        for unwanted in ['http://localhost:80', 'http://testserver']:
            location = location.replace(unwanted, '')
        self.assertEqual(reverse(url_name, kwargs=kwargs), location)

    def assertNoAccess(self, response, msg=None):
        self.assertContext(response)
        self.assertTrue(response.status_code in (http_client.NOT_FOUND, http_client.FORBIDDEN), msg)

    def assertIsOk(self, response, msg=None):
        self.assertEqual(http_client.OK, response.status_code, msg)

    def assertContext(self, response):
        self.assertTrue(response.context is not None, 'No context was returned')

    def assertInContext(self, response, key):
        self.assertContext(response)
        self.assertTrue(key in response.context, "Context should contain a variable '%s'" % key)

    def assertNotInContext(self, response, key):
        self.assertContext(response)
        self.assertTrue(key not in response.context, "Context should not contain a variable '%s'" % key)

class ThumbnailMixin:

    @classmethod
    def setUpClass(cls):
        super().setUpClass()
        remove_image_folders()

    def setUp(self):
        super().setUp()
        self.thumbnail_options = {'size': 'x50', 'upscale': False}

    def tearDown(self):
        super().tearDown()
        remove_image_folders()

    def create_product_images(self, qty=2, product=None):
        self._test_images_folder_is_empty()
        kwargs = {}
        if product is not None:
            kwargs['product'] = product
        self.images = ProductImageFactory.create_batch(qty, **kwargs)
        file_names = os.listdir(FULL_PATH_TO_IMAGES_FOLDER)
        assert len(file_names) == qty

    def create_thumbnails(self):
        thumbnailer = get_thumbnailer()
        thumbnails_full_paths = []
        for image in self.images:
            thumbnail = thumbnailer.generate_thumbnail(image.original, **self.thumbnail_options)
            thumbnails_full_paths.append(get_thumbnail_full_path(thumbnail.url))
        for path in thumbnails_full_paths:
            assert os.path.isfile(path)
        return thumbnails_full_paths

    def _test_images_folder_is_empty(self):
        if not os.path.exists(FULL_PATH_TO_IMAGES_FOLDER):
            os.makedirs(FULL_PATH_TO_IMAGES_FOLDER)
        file_names = os.listdir(FULL_PATH_TO_IMAGES_FOLDER)
        assert len(file_names) == 0

    def _test_thumbnails_not_exist(self, thumbnails_full_paths):
        for path in thumbnails_full_paths:
            assert not os.path.isfile(path)

class PostActionMixin:
    """
    Simple mixin to forward POST request that contain a key 'action'
    onto a method of form "do_{action}".

    This only works with DetailView
    """

    def post(self, request, *args, **kwargs):
        if 'action' in self.request.POST:
            model = self.get_object()
            method_name = 'do_%s' % self.request.POST['action'].lower()
            if hasattr(self, method_name):
                getattr(self, method_name)(model)
                return self.response
            else:
                messages.error(request, _('Invalid form submission'))
                return self.get(request, *args, **kwargs)
        try:
            return super().post(request, *args, **kwargs)
        except AttributeError:
            messages.error(request, _('Invalid form submission'))
            return self.get(request, *args, **kwargs)

class BulkEditMixin:
    """
    Mixin for views that have a bulk editing facility.  This is normally in the
    form of tabular data where each row has a checkbox.  The UI allows a number
    of rows to be selected and then some 'action' to be performed on them.
    """
    action_param = 'action'
    select_across_param = 'select_across'
    actions = None
    checkbox_object_name = None

    def get_checkbox_object_name(self):
        if self.checkbox_object_name:
            return self.checkbox_object_name
        return smart_str(self.model._meta.object_name.lower())

    def get_error_url(self, request):
        return safe_referrer(request, '.')

    def get_success_url(self, request):
        return safe_referrer(request, '.')

    def post(self, request, *args, **kwargs):
        action = request.POST.get(self.action_param, '').lower()
        all_selections = self.request.POST.get(self.select_across_param, '').lower()
        if not self.actions or action not in self.actions:
            messages.error(self.request, _('Invalid action'))
            return redirect(self.get_error_url(request))
        if all_selections == '1':
            objects = self.get_queryset()
        else:
            ids = request.POST.getlist('selected_%s' % self.get_checkbox_object_name())
            ids = list(map(int, ids))
            if not ids:
                messages.error(self.request, _('You need to select some %ss') % self.get_checkbox_object_name())
                return redirect(self.get_error_url(request))
            objects = self.get_objects(ids)
        return getattr(self, action)(request, objects)

    def get_objects(self, ids):
        object_dict = self.get_object_dict(ids)
        return [object_dict[id] for id in ids if id in object_dict]

    def get_object_dict(self, ids):
        return self.get_queryset().in_bulk(ids)

class ObjectLookupView(View):
    """Base view for json lookup for objects"""

    def get_queryset(self):
        return self.model.objects.all()

    def format_object(self, obj):
        return {'id': obj.pk, 'text': str(obj)}

    def initial_filter(self, qs, value):
        return qs.filter(pk__in=value.split(','))

    def lookup_filter(self, qs, term):
        return qs

    def paginate(self, qs, page, page_limit):
        total = qs.count()
        start = (page - 1) * page_limit
        stop = start + page_limit
        qs = qs[start:stop]
        return (qs, page_limit * page < total)

    def get_args(self):
        GET = self.request.GET
        return (GET.get('initial', None), GET.get('q', None), int(GET.get('page', 1)), int(GET.get('page_limit', 20)))

    def get(self, request):
        self.request = request
        qs = self.get_queryset()
        initial, q, page, page_limit = self.get_args()
        if initial:
            qs = self.initial_filter(qs, initial)
            more = False
        else:
            if q:
                qs = self.lookup_filter(qs, q)
            qs, more = self.paginate(qs, page, page_limit)
        return JsonResponse({'results': [self.format_object(obj) for obj in qs], 'pagination': {'more': more}})

