class LineOfferConsumer(object):
    """
    facade for marking basket lines as consumed by
    any or a specific offering.

    historically oscar marks a line as consumed if any
    offer is applied to it, but more complicated scenarios
    are possible if we mark the line as being consumed by
    specific offers.

    this allows combining i.e. multiple vouchers, vouchers
    with special session discounts, etc.
    """

    def __init__(self, line):
        self._line = line
        self._offers = dict()
        self._affected_quantity = 0
        self._consumptions = defaultdict(int)

    def _cache(self, offer):
        self._offers[offer.pk] = offer

    def _update_affected_quantity(self, quantity):
        available = int(self._line.quantity - self._affected_quantity)
        num_consumed = min(available, quantity)
        self._affected_quantity += num_consumed
        return num_consumed

    def consume(self, quantity: int, offer=None):
        """
        mark a basket line as consumed by an offer

        :param int quantity: the number of items on the line affected
        :param offer: the offer to mark the line
        :type offer: ConditionalOffer or None
        :return: the number of items actually consumed
        :rtype: int

        if offer is None, the specified quantity of items on this
        basket line is consumed for *any* offer, else only for the
        specified offer.
        """
        if offer:
            self._cache(offer)
            available = self.available(offer)
        num_consumed = self._update_affected_quantity(quantity)
        if offer:
            num_consumed = min(available, quantity)
            self._consumptions[offer.pk] += num_consumed
        return num_consumed

    @deprecated
    def consumed(self, offer=None):
        return self.num_consumed(offer)

    def num_consumed(self, offer=None):
        """
        check how many items on this line have been
        consumed by an offer

        :param offer: the offer to check
        :type offer: ConditionalOffer or None
        :return: the number of items marked as consumed
        :rtype: int

        if offer is not None, only the number of items marked
        with the specified ConditionalOffer are returned

        """
        if not offer:
            return self._affected_quantity
        return int(self._consumptions[offer.pk])

    @property
    def consumers(self):
        return [x for x in self._offers.values() if self.num_consumed(x)]

    def available(self, offer=None) -> int:
        """
        check how many items are available for offer

        :param offer: the offer to check
        :type offer: ConditionalOffer or None
        :return: the number of items available for offer
        :rtype: int
        """
        max_affected_items = self._line.quantity
        if offer and isinstance(offer, ConditionalOffer):
            applied = [x for x in self.consumers if x != offer]
            if offer.exclusive:
                for a in applied:
                    if a.exclusive:
                        if any([a.priority > offer.priority, a.priority == offer.priority and a.id != offer.id]):
                            max_affected_items = max_affected_items - self.num_consumed(a)
                            if max_affected_items == 0:
                                return 0
                    else:
                        return 0
            elif any([x.exclusive for x in applied]):
                return 0
            for x in applied:
                check = offer.combinations.count() or x.combinations.count()
                if check and offer not in x.combined_offers:
                    return 0
        return max_affected_items - self.num_consumed(offer)

class LineDiscountRegistry(LineOfferConsumer):

    def __init__(self, line):
        super().__init__(line)
        self._discounts = []
        self._discount_excl_tax = None
        self._discount_incl_tax = None

    def discount(self, amount, quantity, incl_tax=True, offer=None):
        self._discounts.append(DiscountApplication(amount, quantity, incl_tax, offer))
        self.consume(quantity, offer=offer)
        if incl_tax:
            self._discount_incl_tax = None
        else:
            self._discount_excl_tax = None

    @property
    def excl_tax(self):
        if self._discount_excl_tax is None:
            self._discount_excl_tax = sum([d.amount for d in self._discounts if not d.incl_tax], 0)
        return self._discount_excl_tax

    @property
    def incl_tax(self):
        if self._discount_incl_tax is None:
            self._discount_incl_tax = sum([d.amount for d in self._discounts if d.incl_tax], 0)
        return self._discount_incl_tax

    @property
    def total(self):
        return sum([d.amount for d in self._discounts], 0)

    def all(self):
        return self._discounts

    def __iter__(self):
        return iter(self._discounts)

class BasketView(ModelFormSetView):
    model = get_model('basket', 'Line')
    basket_model = get_model('basket', 'Basket')
    formset_class = BasketLineFormSet
    form_class = BasketLineForm
    factory_kwargs = {'extra': 0, 'can_delete': True}
    template_name = 'oscar/basket/basket.html'

    def get_formset_kwargs(self):
        kwargs = super().get_formset_kwargs()
        kwargs['strategy'] = self.request.strategy
        return kwargs

    def get_queryset(self):
        """
        Return list of :py:class:`Line <oscar.apps.basket.abstract_models.AbstractLine>`
        instances associated with the current basket.
        """
        return self.request.basket.all_lines()

    def get_shipping_methods(self, basket):
        return Repository().get_shipping_methods(basket=self.request.basket, user=self.request.user, request=self.request)

    def get_default_shipping_address(self):
        if self.request.user.is_authenticated:
            return self.request.user.addresses.filter(is_default_for_shipping=True).first()

    def get_default_shipping_method(self, basket):
        return Repository().get_default_shipping_method(basket=self.request.basket, user=self.request.user, request=self.request, shipping_addr=self.get_default_shipping_address())

    def get_basket_warnings(self, basket):
        """
        Return a list of warnings that apply to this basket
        """
        warnings = []
        for line in basket.all_lines():
            warning = line.get_warning()
            if warning:
                warnings.append(warning)
        return warnings

    def get_upsell_messages(self, basket):
        offers = Applicator().get_offers(basket, self.request.user, self.request)
        applied_offers = list(basket.offer_applications.offers.values())
        msgs = []
        for offer in offers:
            if offer.is_condition_partially_satisfied(basket) and offer not in applied_offers:
                data = {'message': offer.get_upsell_message(basket), 'offer': offer}
                msgs.append(data)
        return msgs

    def get_basket_voucher_form(self):
        """
        This is a separate method so that it's easy to e.g. not return a form
        if there are no vouchers available.
        """
        return BasketVoucherForm()

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['voucher_form'] = self.get_basket_voucher_form()
        context['shipping_methods'] = self.get_shipping_methods(self.request.basket)
        method = self.get_default_shipping_method(self.request.basket)
        context['shipping_method'] = method
        shipping_charge = method.calculate(self.request.basket)
        context['shipping_charge'] = shipping_charge
        if method.is_discounted:
            excl_discount = method.calculate_excl_discount(self.request.basket)
            context['shipping_charge_excl_discount'] = excl_discount
        context['basket_warnings'] = self.get_basket_warnings(self.request.basket)
        context['upsell_messages'] = self.get_upsell_messages(self.request.basket)
        if self.request.user.is_authenticated:
            try:
                saved_basket = self.basket_model.saved.get(owner=self.request.user)
            except self.basket_model.DoesNotExist:
                pass
            else:
                saved_basket.strategy = self.request.basket.strategy
                if not saved_basket.is_empty:
                    saved_queryset = saved_basket.all_lines()
                    formset = SavedLineFormSet(strategy=self.request.strategy, basket=self.request.basket, queryset=saved_queryset, prefix='saved')
                    context['saved_formset'] = formset
        surcharges = SurchargeApplicator(self.request, context).get_applicable_surcharges(self.request.basket, shipping_charge=shipping_charge)
        context['surcharges'] = surcharges
        context['order_total'] = OrderTotalCalculator().calculate(self.request.basket, shipping_charge, surcharges=surcharges)
        return context

    def get_success_url(self):
        return safe_referrer(self.request, 'basket:summary')

    def formset_valid(self, formset):
        offers_before = self.request.basket.applied_offers()
        save_for_later = False
        flash_messages = ajax.FlashMessages()
        for form in formset:
            if hasattr(form, 'cleaned_data') and form.cleaned_data.get('save_for_later', False):
                line = form.instance
                if self.request.user.is_authenticated:
                    self.move_line_to_saved_basket(line)
                    msg = render_to_string('oscar/basket/messages/line_saved.html', {'line': line})
                    flash_messages.info(msg)
                    save_for_later = True
                else:
                    msg = _("You can't save an item for later if you're not logged in!")
                    flash_messages.error(msg)
                    return redirect(self.get_success_url())
        if save_for_later:
            response = redirect(self.get_success_url())
        else:
            response = super().formset_valid(formset)
        if is_ajax(self.request):
            self.request.basket = get_model('basket', 'Basket').objects.get(id=self.request.basket.id)
            self.request.basket.strategy = self.request.strategy
            Applicator().apply(self.request.basket, self.request.user, self.request)
            offers_after = self.request.basket.applied_offers()
            for level, msg in BasketMessageGenerator().get_messages(self.request.basket, offers_before, offers_after, include_buttons=False):
                flash_messages.add_message(level, msg)
            kwargs = self.get_formset_kwargs()
            del kwargs['data']
            del kwargs['files']
            if 'queryset' in kwargs:
                del kwargs['queryset']
            formset = self.get_formset()(queryset=self.get_queryset(), **kwargs)
            ctx = self.get_context_data(formset=formset, basket=self.request.basket)
            return self.json_response(ctx, flash_messages)
        BasketMessageGenerator().apply_messages(self.request, offers_before)
        return response

    def json_response(self, ctx, flash_messages):
        basket_html = render_to_string('oscar/basket/partials/basket_content.html', context=ctx, request=self.request)
        return JsonResponse({'content_html': basket_html, 'messages': flash_messages.as_dict()})

    def move_line_to_saved_basket(self, line):
        saved_basket, _ = get_model('basket', 'basket').saved.get_or_create(owner=self.request.user)
        saved_basket.merge_line(line)

    def formset_invalid(self, formset):
        has_deletion = any((formset._should_delete_form(form) for form in formset.forms))
        has_no_invalid_non_deletion = all((form.is_valid() or formset._should_delete_form(form) for form in formset.forms))
        if has_deletion:
            self.remove_deleted_forms(formset)
            if has_no_invalid_non_deletion:
                return self.formset_valid(formset)
        flash_messages = ajax.FlashMessages()
        flash_messages.warning(_('Your basket has got some issues. Please correct any validation errors below.'))
        if is_ajax(self.request):
            ctx = self.get_context_data(formset=formset, basket=self.request.basket)
            return self.json_response(ctx, flash_messages)
        flash_messages.apply_to_request(self.request)
        return super().formset_invalid(formset)

    def remove_deleted_forms(self, formset):
        """
        Removes forms marked for deletion, from the formset, as well as deletes
        their model instance objects; and modifies the formset's request data,
        to match the state of the data in the database, for the remaining forms.

        This is useful for redisplaying a formset containing other invalid
        forms, after deleting one of the forms from it.
        """
        form_data = {}
        form_index = 0
        for form in formset.forms:
            if formset._should_delete_form(form):
                if form.instance.id is not None:
                    form.instance.delete()
            else:
                old_form_prefix = form.prefix
                new_form_prefix = formset.add_prefix(form_index)
                for field_name in form.fields:
                    form.prefix = old_form_prefix
                    old_prefixed_field_name = form.add_prefix(field_name)
                    form.prefix = new_form_prefix
                    new_prefixed_field_name = form.add_prefix(field_name)
                    try:
                        form_data[new_prefixed_field_name] = formset.data[old_prefixed_field_name]
                    except KeyError:
                        pass
                form_index += 1
        for field_name in formset.management_form.fields:
            prefixed_field_name = formset.management_form.add_prefix(field_name)
            if field_name in ['INITIAL_FORMS', 'TOTAL_FORMS']:
                form_data[prefixed_field_name] = str(form_index)
            else:
                form_data[prefixed_field_name] = formset.data[prefixed_field_name]
        query_dict = QueryDict(mutable=True)
        query_dict.update(form_data)
        formset.data = query_dict
        del formset.management_form
        del formset.forms
        formset.full_clean()

class BasketAddView(FormView):
    """
    Handles the add-to-basket submissions, which are triggered from various
    parts of the site. The add-to-basket form is loaded into templates using
    a templatetag from :py:mod:`oscar.templatetags.basket_tags`.
    """
    form_class = AddToBasketForm
    product_model = get_model('catalogue', 'product')
    add_signal = basket_addition
    http_method_names = ['post']

    def post(self, request, *args, **kwargs):
        self.product = shortcuts.get_object_or_404(self.product_model, pk=kwargs['pk'])
        return super().post(request, *args, **kwargs)

    def get_form_kwargs(self):
        kwargs = super().get_form_kwargs()
        kwargs['basket'] = self.request.basket
        kwargs['product'] = self.product
        return kwargs

    def form_invalid(self, form):
        msgs = []
        for error in form.errors.values():
            msgs.append(error.as_text())
        clean_msgs = [m.replace('* ', '') for m in msgs if m.startswith('* ')]
        messages.error(self.request, ','.join(clean_msgs))
        serialized_data = JSONSerializer().dumps(self.request.POST)
        self.request.session['add_to_basket_form_post_data_%s' % self.product.pk] = serialized_data.decode('latin-1')
        return redirect_to_referrer(self.request, 'basket:summary')

    def form_valid(self, form):
        offers_before = self.request.basket.applied_offers()
        self.line, self.line_created = self.request.basket.add_product(form.product, form.cleaned_data['quantity'], form.cleaned_options())
        messages.success(self.request, self.get_success_message(form), extra_tags='safe noicon')
        BasketMessageGenerator().apply_messages(self.request, offers_before)
        self.add_signal.send(sender=self, product=form.product, user=self.request.user, request=self.request)
        return super().form_valid(form)

    def get_success_message(self, form):
        return render_to_string('oscar/basket/messages/addition.html', {'product': form.product, 'quantity': form.cleaned_data['quantity']})

    def get_success_url(self):
        post_url = self.request.POST.get('next')
        if post_url and url_has_allowed_host_and_scheme(post_url, self.request.get_host()):
            return post_url
        return safe_referrer(self.request, 'basket:summary')

class VoucherAddView(FormView):
    form_class = BasketVoucherForm
    voucher_model = get_model('voucher', 'voucher')
    add_signal = voucher_addition

    def get(self, request, *args, **kwargs):
        return redirect('basket:summary')

    def apply_voucher_to_basket(self, voucher):
        if voucher.is_expired():
            messages.error(self.request, _("The '%(code)s' voucher has expired") % {'code': voucher.code})
            return
        if not voucher.is_active():
            messages.error(self.request, _("The '%(code)s' voucher is not active") % {'code': voucher.code})
            return
        is_available, message = voucher.is_available_to_user(self.request.user)
        if not is_available:
            messages.error(self.request, message)
            return
        self.request.basket.vouchers.add(voucher)
        self.add_signal.send(sender=self, basket=self.request.basket, voucher=voucher)
        Applicator().apply(self.request.basket, self.request.user, self.request)
        discounts_after = self.request.basket.offer_applications
        found_discount = False
        for discount in discounts_after:
            if discount['voucher'] and discount['voucher'] == voucher:
                found_discount = True
                break
        if not found_discount:
            messages.warning(self.request, _('Your basket does not qualify for a voucher discount'))
            self.request.basket.vouchers.remove(voucher)
        else:
            messages.info(self.request, _("Voucher '%(code)s' added to basket") % {'code': voucher.code})

    def form_valid(self, form):
        code = form.cleaned_data['code']
        if not self.request.basket.id:
            return redirect_to_referrer(self.request, 'basket:summary')
        if self.request.basket.contains_voucher(code):
            messages.error(self.request, _("You have already added the '%(code)s' voucher to your basket") % {'code': code})
        else:
            try:
                voucher = self.voucher_model._default_manager.get(code=code)
            except self.voucher_model.DoesNotExist:
                messages.error(self.request, _("No voucher found with code '%(code)s'") % {'code': code})
            else:
                self.apply_voucher_to_basket(voucher)
        return redirect_to_referrer(self.request, 'basket:summary')

    def form_invalid(self, form):
        messages.error(self.request, _('Please enter a voucher code'))
        return redirect(reverse('basket:summary') + '#voucher')

class VoucherRemoveView(View):
    voucher_model = get_model('voucher', 'voucher')
    remove_signal = voucher_removal
    http_method_names = ['post']

    def post(self, request, *args, **kwargs):
        response = redirect('basket:summary')
        voucher_id = kwargs['pk']
        if not request.basket.id:
            return response
        try:
            voucher = request.basket.vouchers.get(id=voucher_id)
        except ObjectDoesNotExist:
            messages.error(request, _("No voucher found with id '%s'") % voucher_id)
        else:
            request.basket.vouchers.remove(voucher)
            self.remove_signal.send(sender=self, basket=request.basket, voucher=voucher)
            messages.info(request, _("Voucher '%s' removed from basket") % voucher.code)
        return response

class SavedView(ModelFormSetView):
    model = get_model('basket', 'line')
    basket_model = get_model('basket', 'basket')
    formset_class = SavedLineFormSet
    form_class = SavedLineForm
    factory_kwargs = {'extra': 0, 'can_delete': True}

    def get(self, request, *args, **kwargs):
        return redirect('basket:summary')

    def get_queryset(self):
        """
        Return list of :py:class:`Line <oscar.apps.basket.abstract_models.AbstractLine>`
        instances associated with the saved basked associated with the currently
        authenticated user.
        """
        try:
            saved_basket = self.basket_model.saved.get(owner=self.request.user)
            saved_basket.strategy = self.request.strategy
            return saved_basket.all_lines()
        except self.basket_model.DoesNotExist:
            return []

    def get_success_url(self):
        return safe_referrer(self.request, 'basket:summary')

    def get_formset_kwargs(self):
        kwargs = super().get_formset_kwargs()
        kwargs['prefix'] = 'saved'
        kwargs['basket'] = self.request.basket
        kwargs['strategy'] = self.request.strategy
        return kwargs

    def formset_valid(self, formset):
        offers_before = self.request.basket.applied_offers()
        is_move = False
        for form in formset:
            if form.cleaned_data.get('move_to_basket', False):
                is_move = True
                msg = render_to_string('oscar/basket/messages/line_restored.html', {'line': form.instance})
                messages.info(self.request, msg, extra_tags='safe noicon')
                real_basket = self.request.basket
                real_basket.merge_line(form.instance)
        if is_move:
            BasketMessageGenerator().apply_messages(self.request, offers_before)
            response = redirect(self.get_success_url())
        else:
            response = super().formset_valid(formset)
        return response

    def formset_invalid(self, formset):
        messages.error(self.request, '\n'.join((error for ed in formset.errors for el in ed.values() for error in el)))
        return redirect_to_referrer(self.request, 'basket:summary')

class ReverseStartsWith(StartsWith):
    """
    Adds a new lookup method to the django query language, that allows the
    following syntax::

        henk__rstartswith="koe"

    The regular version of startswith::

        henk__startswith="koe"

     Would be about the same as the python statement::

        henk.startswith("koe")

    ReverseStartsWith will flip the right and left hand side of the expression,
    effectively making this the same query as::

    "koe".startswith(henk)
    """

    def process_lhs(self, compiler, connection, lhs=None):
        if lhs is not None:
            raise Exception('Flipped process_lhs does not accept lhs argument')
        sql, params = super().process_rhs(compiler, connection)
        return (sql, list(params))

    def process_rhs(self, qn, connection):
        return super().process_lhs(qn, connection)

class AbstractCategory(MP_Node):
    """
    A product category. Merely used for navigational purposes; has no
    effects on business logic.

    Uses :py:mod:`django-treebeard`.
    """
    COMPARISON_FIELDS = ('pk', 'path', 'depth')
    name = models.CharField(_('Name'), max_length=255, db_index=True)
    code = NullCharField(_('Code'), max_length=255, blank=True, null=True, unique=True)
    description = models.TextField(_('Description'), blank=True)
    long_description = models.TextField(_('Long description'), blank=True)
    meta_title = models.CharField(_('Meta title'), max_length=255, blank=True, null=True)
    meta_description = models.TextField(_('Meta description'), blank=True, null=True)
    image = models.ImageField(_('Image'), upload_to='categories', blank=True, null=True, max_length=255)
    slug = SlugField(_('Slug'), max_length=255, db_index=True)
    exclude_from_menu = models.BooleanField(_('Exclude from menu'), default=False, db_index=True, help_text=_('Exclude this category from the menu.'))
    is_public = models.BooleanField(_('Is public'), default=True, db_index=True, help_text=_('Show this category in search results and catalogue listings.'))
    ancestors_are_public = models.BooleanField(_('Ancestor categories are public'), default=True, db_index=True, help_text=_('The ancestors of this category are public'))
    _slug_separator = '/'
    _full_name_separator = ' > '
    objects = CategoryQuerySet.as_manager()

    def __str__(self):
        return self.full_name

    @property
    def full_name(self):
        """
        Returns a string representation of the category and it's ancestors,
        e.g. 'Books > Non-fiction > Essential programming'.

        It's rarely used in Oscar, but used to be stored as a CharField and is
        hence kept for backwards compatibility. It's also sufficiently useful
        to keep around.
        """
        names = [category.name for category in self.get_ancestors_and_self()]
        return self._full_name_separator.join(names)

    def get_full_slug(self, parent_slug=None):
        if self.is_root():
            return self.slug
        cache_key = self.get_url_cache_key()
        full_slug = cache.get(cache_key)
        if full_slug is None:
            parent_slug = parent_slug if parent_slug is not None else self.get_parent().full_slug
            full_slug = '%s%s%s' % (parent_slug, self._slug_separator, self.slug)
            cache.set(cache_key, full_slug)
        return full_slug

    @property
    def full_slug(self):
        """
        Returns a string of this category's slug concatenated with the slugs
        of it's ancestors, e.g. 'books/non-fiction/essential-programming'.

        Oscar used to store this as in the 'slug' model field, but this field
        has been re-purposed to only store this category's slug and to not
        include it's ancestors' slugs.
        """
        return self.get_full_slug()

    def generate_slug(self):
        """
        Generates a slug for a category. This makes no attempt at generating
        a unique slug.
        """
        return slugify(self.name)

    def save(self, *args, **kwargs):
        """
        Oscar traditionally auto-generated slugs from names. As that is
        often convenient, we still do so if a slug is not supplied through
        other means. If you want to control slug creation, just create
        instances with a slug already set, or expose a field on the
        appropriate forms.
        """
        if not self.slug:
            self.slug = self.generate_slug()
        super().save(*args, **kwargs)

    def set_ancestors_are_public(self):
        included_in_non_public_subtree = self.__class__.objects.filter(is_public=False, path__rstartswith=OuterRef('path'), depth__lt=OuterRef('depth'))
        self.get_descendants_and_self().update(ancestors_are_public=~Exists(included_in_non_public_subtree.values('id')))
        self.refresh_from_db()

    def get_public_children(self):
        children = self.get_children()
        return children.filter(is_public=True)

    @classmethod
    def fix_tree(cls, fix_paths=False, **kwargs):
        super().fix_tree(fix_paths=fix_paths, **kwargs)
        for node in cls.get_root_nodes():
            if not node.ancestors_are_public:
                node.ancestors_are_public = True
                node.save()
            else:
                node.set_ancestors_are_public()

    def get_meta_title(self):
        return self.meta_title or self.name

    def get_meta_description(self):
        return self.meta_description or striptags(self.description)

    def get_ancestors_and_self(self):
        """
        Gets ancestors and includes itself. Use treebeard's get_ancestors
        if you don't want to include the category itself. It's a separate
        function as it's commonly used in templates.
        """
        if self.is_root():
            return [self]
        return list(self.get_ancestors()) + [self]

    def get_descendants_and_self(self):
        """
        Gets descendants and includes itself. Use treebeard's get_descendants
        if you don't want to include the category itself. It's a separate
        function as it's commonly used in templates.
        """
        return self.get_tree(self)

    def get_url_cache_key(self):
        current_locale = get_language()
        cache_key = 'CATEGORY_URL_%s_%s' % (current_locale, self.pk)
        return cache_key

    def _get_absolute_url(self, parent_slug=None):
        """
        Our URL scheme means we have to look up the category's ancestors. As
        that is a bit more expensive, we cache the generated URL. That is
        safe even for a stale cache, as the default implementation of
        ProductCategoryView does the lookup via primary key anyway. But if
        you change that logic, you'll have to reconsider the caching
        approach.
        """
        return reverse('catalogue:category', kwargs={'category_slug': self.get_full_slug(parent_slug=parent_slug), 'pk': self.pk})

    def get_absolute_url(self):
        return self._get_absolute_url()

    class Meta:
        abstract = True
        app_label = 'catalogue'
        ordering = ['path']
        verbose_name = _('Category')
        verbose_name_plural = _('Categories')

    def has_children(self):
        return self.get_children().exists()

    def get_num_children(self):
        return self.get_children_count()

class AbstractProduct(models.Model):
    """
    The base product object

    There's three kinds of products; they're distinguished by the structure
    field.

    - A stand alone product. Regular product that lives by itself.
    - A child product. All child products have a parent product. They're a
      specific version of the parent.
    - A parent product. It essentially represents a set of products.

    An example could be a yoga course, which is a parent product. The different
    times/locations of the courses would be associated with the child products.
    """
    STANDALONE, PARENT, CHILD = ('standalone', 'parent', 'child')
    STRUCTURE_CHOICES = ((STANDALONE, _('Stand-alone product')), (PARENT, _('Parent product')), (CHILD, _('Child product')))
    structure = models.CharField(_('Product structure'), max_length=10, choices=STRUCTURE_CHOICES, default=STANDALONE)
    is_public = models.BooleanField(_('Is public'), default=True, db_index=True, help_text=_('Show this product in search results and catalogue listings.'))
    upc = NullCharField(_('UPC'), max_length=64, blank=True, null=True, unique=True, help_text=_('Universal Product Code (UPC) is an identifier for a product which is not specific to a particular  supplier. Eg an ISBN for a book.'))
    parent = models.ForeignKey('self', blank=True, null=True, on_delete=models.CASCADE, related_name='children', verbose_name=_('Parent product'), help_text=_("Only choose a parent product if you're creating a child product.  For example if this is a size 4 of a particular t-shirt.  Leave blank if this is a stand-alone product (i.e. there is only one version of this product)."))
    title = models.CharField(pgettext_lazy('Product title', 'Title'), max_length=255, blank=True)
    slug = SlugField(_('Slug'), max_length=255, unique=False)
    description = models.TextField(_('Description'), blank=True)
    meta_title = models.CharField(_('Meta title'), max_length=255, blank=True, null=True)
    meta_description = models.TextField(_('Meta description'), blank=True, null=True)
    priority = models.SmallIntegerField(_('Priority'), null=False, default=0, db_index=True, help_text=_('The highest priority products are shown first'), validators=[MinValueValidator(-1)])
    product_class = models.ForeignKey('catalogue.ProductClass', null=True, blank=True, on_delete=models.PROTECT, verbose_name=_('Product type'), related_name='products', help_text=_('Choose what type of product this is'))
    attributes = models.ManyToManyField('catalogue.ProductAttribute', through='ProductAttributeValue', verbose_name=_('Attributes'), help_text=_('A product attribute is something that this product may have, such as a size, as specified by its class'))
    product_options = models.ManyToManyField('catalogue.Option', blank=True, verbose_name=_('Product options'), help_text=_("Options are values that can be associated with a item when it is added to a customer's basket.  This could be something like a personalised message to be printed on a T-shirt."))
    recommended_products = models.ManyToManyField('catalogue.Product', through='ProductRecommendation', blank=True, verbose_name=_('Recommended products'), help_text=_('These are products that are recommended to accompany the main product.'))
    rating = models.FloatField(_('Rating'), null=True, editable=False)
    date_created = models.DateTimeField(_('Date created'), auto_now_add=True, db_index=True)
    date_updated = models.DateTimeField(_('Date updated'), auto_now=True, db_index=True)
    categories = models.ManyToManyField('catalogue.Category', through='ProductCategory', verbose_name=_('Categories'))
    is_discountable = models.BooleanField(_('Is discountable?'), default=True, help_text=_('This flag indicates if this product can be used in an offer or not'))
    code = models.CharField(_("Code can be used to store a secondary unique identifier, when upc isn't sufficient"), max_length=255, blank=True, null=True, unique=True)
    objects = ProductQuerySet.as_manager()

    class Meta:
        abstract = True
        app_label = 'catalogue'
        ordering = ['-date_created']
        verbose_name = _('Product')
        verbose_name_plural = _('Products')

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.attr = ProductAttributesContainer(product=self)

    def __str__(self):
        if self.title:
            return self.title
        if self.attribute_summary:
            return '%s (%s)' % (self.get_title(), self.attribute_summary)
        else:
            return self.get_title()

    def get_absolute_url(self):
        """
        Return a product's absolute URL
        """
        return reverse('catalogue:detail', kwargs={'product_slug': self.slug, 'pk': self.id})

    def clean(self):
        """
        Validate a product. Those are the rules:

        +---------------+-------------+--------------+--------------+
        |               | stand alone | parent       | child        |
        +---------------+-------------+--------------+--------------+
        | title         | required    | required     | optional     |
        +---------------+-------------+--------------+--------------+
        | product class | required    | required     | must be None |
        +---------------+-------------+--------------+--------------+
        | parent        | forbidden   | forbidden    | required     |
        +---------------+-------------+--------------+--------------+
        | stockrecords  | 0 or more   | forbidden    | 0 or more    |
        +---------------+-------------+--------------+--------------+
        | categories    | 1 or more   | 1 or more    | forbidden    |
        +---------------+-------------+--------------+--------------+
        | attributes    | optional    | optional     | optional     |
        +---------------+-------------+--------------+--------------+
        | rec. products | optional    | optional     | unsupported  |
        +---------------+-------------+--------------+--------------+
        | options       | optional    | optional     | forbidden    |
        +---------------+-------------+--------------+--------------+

        Because the validation logic is quite complex, validation is delegated
        to the sub method appropriate for the product's structure.
        """
        getattr(self, '_clean_%s' % self.structure)()
        if not self.is_parent:
            self.attr.validate_attributes()

    def _clean_standalone(self):
        """
        Validates a stand-alone product
        """
        if not self.title:
            raise ValidationError(_('Your product must have a title.'))
        if not self.product_class:
            raise ValidationError(_('Your product must have a product class.'))
        if self.parent_id:
            raise ValidationError(_('Only child products can have a parent.'))

    def _clean_child(self):
        """
        Validates a child product
        """
        has_parent = self.parent or self.parent_id
        if not has_parent:
            raise ValidationError(_('A child product needs a parent.'))
        if has_parent and (not self.parent.is_parent):
            raise ValidationError(_('You can only assign child products to parent products.'))
        if self.product_class:
            raise ValidationError(_("A child product can't have a product class."))
        if self.pk and self.categories.exists():
            raise ValidationError(_("A child product can't have a category assigned."))
        if self.pk and self.product_options.exists():
            raise ValidationError(_("A child product can't have options."))

    def _clean_parent(self):
        """
        Validates a parent product.
        """
        self._clean_standalone()
        if self.has_stockrecords:
            raise ValidationError(_("A parent product can't have stockrecords."))

    def save(self, *args, **kwargs):
        if not self.slug:
            self.slug = slugify(self.get_title())
        super().save(*args, **kwargs)
        self.attr.save()

    def refresh_from_db(self, *args, **kwargs):
        super().refresh_from_db(*args, **kwargs)
        self.attr.invalidate()

    @property
    def is_standalone(self):
        return self.structure == self.STANDALONE

    @property
    def is_parent(self):
        return self.structure == self.PARENT

    @property
    def is_child(self):
        return self.structure == self.CHILD

    def can_be_parent(self, give_reason=False):
        """
        Helps decide if a the product can be turned into a parent product.
        """
        reason = None
        if self.is_child:
            reason = _('The specified parent product is a child product.')
        if self.has_stockrecords:
            reason = _("One can't add a child product to a product with stock records.")
        is_valid = reason is None
        if give_reason:
            return (is_valid, reason)
        else:
            return is_valid

    @property
    def options(self):
        """
        Returns a set of all valid options for this product.
        It's possible to have options product class-wide, and per product.
        """
        pclass_options = self.get_product_class().options.all()
        return pclass_options | self.product_options.all()

    @cached_property
    def has_options(self):
        has_product_class_options = getattr(self, 'has_product_class_options', None)
        has_product_options = getattr(self, 'has_product_options', None)
        if has_product_class_options is not None and has_product_options is not None:
            return has_product_class_options or has_product_options
        return self.options.exists()

    @property
    def is_shipping_required(self):
        return self.get_product_class().requires_shipping

    @property
    def has_stockrecords(self):
        """
        Test if this product has any stockrecords
        """
        if self.id:
            return self.stockrecords.exists()
        return False

    @property
    def num_stockrecords(self):
        return self.stockrecords.count()

    @property
    def attribute_summary(self):
        """
        Return a string of all of a product's attributes
        """
        attributes = self.get_attribute_values()
        pairs = [attribute.summary() for attribute in attributes]
        return ', '.join(pairs)

    def get_title(self):
        """
        Return a product's title or it's parent's title if it has no title
        """
        title = self.title
        if not title and self.parent_id:
            title = self.parent.title
        return title
    get_title.short_description = pgettext_lazy('Product title', 'Title')

    def get_meta_title(self):
        title = self.meta_title
        if not title and self.is_child:
            title = self.parent.meta_title
        return title or self.get_title()
    get_meta_title.short_description = pgettext_lazy('Product meta title', 'Meta title')

    def get_meta_description(self):
        meta_description = self.meta_description
        if not meta_description and self.is_child:
            meta_description = self.parent.meta_description
        return meta_description or striptags(self.description)
    get_meta_description.short_description = pgettext_lazy('Product meta description', 'Meta description')

    def get_product_class(self):
        """
        Return a product's item class. Child products inherit their parent's.
        """
        if self.is_child:
            return self.parent.product_class
        else:
            return self.product_class
    get_product_class.short_description = _('Product class')

    def get_public_children(self):
        """
        Retrieve public children of the product efficiently.

        This method optimizes querying for public children by utilizing prefetched data
        when available. It's particularly useful in scenarios where multiple products
        are being iterated over and their public children need to be accessed, as it
        can significantly reduce the number of database queries.

        Returns:
            QuerySet or list: A queryset of public children if not prefetched,
                              or a list of prefetched public children.
        """
        if hasattr(self, '_prefetched_public_children'):
            return self._prefetched_public_children
        return self.children.public()

    @deprecated
    def get_is_discountable(self):
        """
        It used to be that, :py:attr:`.is_discountable` couldn't be set individually for child
        products; so they had to inherit it from their parent. This is nolonger the case because
        ranges can include child products as well. That make this method useless.
        """
        return self.is_discountable

    def get_categories(self):
        """
        Return a product's public categories or parent's if there is a parent product.
        It also supports prefetching by checking whether _prefetched_browsable_categories
        is been set as attribute on the product.
        """
        if self.is_child:
            if hasattr(self.parent, '_prefetched_browsable_categories'):
                return self.parent._prefetched_browsable_categories
            return self.parent.categories.browsable()
        else:
            if hasattr(self, '_prefetched_browsable_categories'):
                return self._prefetched_browsable_categories
            return self.categories.browsable()
    get_categories.short_description = _('Categories')

    def get_attribute_values(self):
        if hasattr(self, '_prefetched_attribute_values'):
            if self.is_child:
                attribute_values = {item.attribute.code: item for item in self.parent._prefetched_parent_attribute_values}
                for item in self._prefetched_attribute_values:
                    attribute_values[item.attribute.code] = item
                return list(attribute_values.values())
            return self._prefetched_attribute_values
        if not self.pk:
            return self.attribute_values.model.objects.none()
        attribute_values = self.attribute_values.all()
        if self.is_child:
            parent_attribute_values = self.parent.attribute_values.exclude(attribute__code__in=attribute_values.values('attribute__code'))
            return attribute_values | parent_attribute_values
        return attribute_values

    def get_missing_image(self):
        """
        Returns a missing image object.
        """
        return MissingProductImage()

    def get_all_images(self):
        if self.is_child and (not self.images.exists()) and (self.parent_id is not None):
            return self.parent.images.all()
        return self.images.all()

    def primary_image(self):
        """
        Returns the primary image for a product. Usually used when one can
        only display one product image, e.g. in a list of products.
        """
        images = self.get_all_images()
        ordering = self.images.model._meta.ordering
        if not ordering or ordering[0] != 'display_order':
            images = images.order_by('display_order')
        try:
            return images[0]
        except IndexError:
            missing_image = self.get_missing_image()
            return {'original': missing_image.name, 'caption': '', 'is_missing': True}

    def update_rating(self):
        """
        Recalculate rating field
        """
        self.rating = self.calculate_rating()
        self.save()
    update_rating.alters_data = True

    def calculate_rating(self):
        """
        Calculate rating value
        """
        result = self.reviews.filter(status=self.reviews.model.APPROVED).aggregate(sum=Sum('score'), count=Count('id'))
        reviews_sum = result['sum'] or 0
        reviews_count = result['count'] or 0
        rating = None
        if reviews_count > 0:
            rating = float(reviews_sum) / reviews_count
        return rating

    def has_review_by(self, user):
        if user.is_anonymous:
            return False
        return self.reviews.filter(user=user).exists()

    def is_review_permitted(self, user):
        """
        Determines whether a user may add a review on this product.

        Default implementation respects OSCAR_ALLOW_ANON_REVIEWS and only
        allows leaving one review per user and product.

        Override this if you want to alter the default behaviour; e.g. enforce
        that a user purchased the product to be allowed to leave a review.
        """
        if user.is_authenticated or settings.OSCAR_ALLOW_ANON_REVIEWS:
            return not self.has_review_by(user)
        else:
            return False

    @cached_property
    def num_approved_reviews(self):
        return self.reviews.approved().count()

    @property
    def sorted_recommended_products(self):
        """Keeping order by recommendation ranking."""
        return [r.recommendation for r in self.primary_recommendations.select_related('recommendation').all()]

class AbstractProductAttribute(models.Model):
    """
    Defines an attribute for a product class. (For example, number_of_pages for
    a 'book' class)
    """
    product_class = models.ForeignKey('catalogue.ProductClass', blank=True, on_delete=models.CASCADE, related_name='attributes', null=True, verbose_name=_('Product type'))
    name = models.CharField(_('Name'), max_length=128)
    code = models.SlugField(_('Code'), max_length=128, validators=[RegexValidator(regex='^[a-zA-Z_][0-9a-zA-Z_]*$', message=_("Code can only contain the letters a-z, A-Z, digits, and underscores, and can't start with a digit.")), non_python_keyword])
    TEXT = 'text'
    INTEGER = 'integer'
    BOOLEAN = 'boolean'
    FLOAT = 'float'
    RICHTEXT = 'richtext'
    DATE = 'date'
    DATETIME = 'datetime'
    OPTION = 'option'
    MULTI_OPTION = 'multi_option'
    ENTITY = 'entity'
    FILE = 'file'
    IMAGE = 'image'
    TYPE_CHOICES = ((TEXT, _('Text')), (INTEGER, _('Integer')), (BOOLEAN, _('True / False')), (FLOAT, _('Float')), (RICHTEXT, _('Rich Text')), (DATE, _('Date')), (DATETIME, _('Datetime')), (OPTION, _('Option')), (MULTI_OPTION, _('Multi Option')), (ENTITY, _('Entity')), (FILE, _('File')), (IMAGE, _('Image')))
    type = models.CharField(choices=TYPE_CHOICES, default=TYPE_CHOICES[0][0], max_length=20, verbose_name=_('Type'))
    option_group = models.ForeignKey('catalogue.AttributeOptionGroup', blank=True, null=True, on_delete=models.CASCADE, related_name='product_attributes', verbose_name=_('Option Group'), help_text=_('Select an option group if using type "Option" or "Multi Option"'))
    required = models.BooleanField(_('Required'), default=False)

    class Meta:
        abstract = True
        app_label = 'catalogue'
        ordering = ['code']
        verbose_name = _('Product attribute')
        verbose_name_plural = _('Product attributes')
        unique_together = ('code', 'product_class')

    @property
    def is_option(self):
        return self.type == self.OPTION

    @property
    def is_multi_option(self):
        return self.type == self.MULTI_OPTION

    @property
    def is_file(self):
        return self.type in [self.FILE, self.IMAGE]

    @property
    def is_entity(self):
        return self.type == self.ENTITY

    def __str__(self):
        return self.name

    def clean(self):
        if self.type == self.BOOLEAN and self.required:
            raise ValidationError(_('Boolean attribute should not be required.'))

    def _get_value_obj(self, product, value):
        try:
            return product.attribute_values.get(attribute=self)
        except ObjectDoesNotExist:
            delete_file = self.is_file and value is False
            if value is None or value == '' or delete_file:
                return None
            return product.attribute_values.create(attribute=self)

    def _bind_value_file(self, value_obj, value):
        if value is None:
            return value_obj
        elif value is False:
            return None
        else:
            value_obj.value = value
            return value_obj

    def _bind_value_multi_option(self, value_obj, value):
        if value is None:
            return None
        try:
            count = value.count()
        except (AttributeError, TypeError):
            count = len(value)
        if count == 0:
            return None
        else:
            value_obj.value = value
            return value_obj

    def _bind_value(self, value_obj, value):
        if value is None or value == '':
            return None
        value_obj.value = value
        return value_obj

    def bind_value(self, value_obj, value):
        """
        bind_value will bind the value passed to the value_obj, if the bind_value
        return None, that means the value_obj is supposed to be deleted.
        """
        if self.is_file:
            return self._bind_value_file(value_obj, value)
        elif self.is_multi_option:
            return self._bind_value_multi_option(value_obj, value)
        else:
            return self._bind_value(value_obj, value)

    def save_value(self, product, value):
        value_obj = self._get_value_obj(product, value)
        if value_obj is None:
            return None
        updated_value_obj = self.bind_value(value_obj, value)
        if updated_value_obj is None:
            value_obj.delete()
        elif updated_value_obj.is_dirty:
            updated_value_obj.save()
        return updated_value_obj

    def validate_value(self, value):
        validator = getattr(self, '_validate_%s' % self.type)
        validator(value)

    def _validate_text(self, value):
        if not isinstance(value, str):
            raise ValidationError(_('Must be str'))
    _validate_richtext = _validate_text

    def _validate_float(self, value):
        try:
            float(value)
        except ValueError:
            raise ValidationError(_('Must be a float'))

    def _validate_integer(self, value):
        try:
            int(value)
        except ValueError:
            raise ValidationError(_('Must be an integer'))

    def _validate_date(self, value):
        if not (isinstance(value, datetime) or isinstance(value, date)):
            raise ValidationError(_('Must be a date or datetime'))

    def _validate_datetime(self, value):
        if not isinstance(value, datetime):
            raise ValidationError(_('Must be a datetime'))

    def _validate_boolean(self, value):
        if not type(value) == bool:
            raise ValidationError(_('Must be a boolean'))

    def _validate_entity(self, value):
        if not isinstance(value, models.Model):
            raise ValidationError(_('Must be a model instance'))

    def _validate_multi_option(self, value):
        try:
            values = iter(value)
        except TypeError:
            raise ValidationError(_('Must be a list or AttributeOption queryset'))
        valid_values = self.option_group.options.values_list('option', flat=True)
        for value in values:
            self._validate_option(value, valid_values=valid_values)

    def _validate_option(self, value, valid_values=None):
        if not isinstance(value, get_model('catalogue', 'AttributeOption')):
            raise ValidationError(_('Must be an AttributeOption model object instance'))
        if not value.pk:
            raise ValidationError(_('AttributeOption has not been saved yet'))
        if valid_values is None:
            valid_values = self.option_group.options.values_list('option', flat=True)
        if value.option not in valid_values:
            raise ValidationError(_('%(enum)s is not a valid choice for %(attr)s') % {'enum': value, 'attr': self})

    def _validate_file(self, value):
        if value and (not isinstance(value, File)):
            raise ValidationError(_('Must be a file field'))
    _validate_image = _validate_file

