class AttributeFilter(dict):
    """
    Utility class used to implement the filter_by_attributes functionality.

    handles lookups, options and multivalue properties, check the tests for
    all features.
    """

    def __init__(self, filter_kwargs):
        super(AttributeFilter, self).__init__()
        for key, value in filter_kwargs.items():
            if LOOKUP_SEP in key:
                field_name, lookup = key.split(LOOKUP_SEP, 1)
                self[field_name] = (lookup, value)
            else:
                self[key] = (None, value)

    def field_names(self):
        return self.keys()

    def _selector(self, attribute_type):
        if attribute_type == 'option' or attribute_type == 'multi_option':
            return 'attribute_values__value_%s__option' % attribute_type
        else:
            return 'attribute_values__value_%s' % attribute_type

    def _select_value(self, types, lookup, value):
        _filter = models.Q()
        for _type in types:
            sel = self._selector(_type)
            if lookup is not None:
                sel = '%s%s%s' % (sel, LOOKUP_SEP, lookup)
            kwargs = dict()
            kwargs[sel] = value
            _filter |= models.Q(**kwargs)
        return _filter

    def fast_query(self, attribute_types, queryset):
        qs = queryset
        typedict = defaultdict(list)
        for code, attribute_type in attribute_types:
            typedict[code].append(attribute_type)
        for code, (lookup, value) in self.items():
            selected_values = self._select_value(typedict[code], lookup, value)
            if not selected_values:
                return queryset.none()
            qs = qs.filter(selected_values, attribute_values__attribute__code=code)
        return qs

class CategoryQuerySet(MP_NodeQuerySet):

    def browsable(self):
        """
        Excludes non-public categories
        """
        return self.filter(is_public=True, ancestors_are_public=True)

    def for_menu(self):
        """
        Browsable categories that are not excluded for the menu
        """
        excluded_paths = list(self.browsable().filter(exclude_from_menu=True).values_list('path', flat=True))
        qs = self.browsable().filter(exclude_from_menu=False)
        if excluded_paths:
            condition = Q()
            for path in excluded_paths:
                condition |= Q(path__startswith=path)
            qs = qs.exclude(condition)
        return qs

class QuerysetCache(dict):

    def __init__(self, queryset):
        self._queryset = queryset
        if isinstance(queryset, list):
            self._queryset_iterator = queryset
        else:
            self._queryset_iterator = queryset.iterator()

    def queryset(self):
        return self._queryset

    def get(self, code, default=None):
        try:
            return self[code]
        except KeyError:
            for instance in self._queryset_iterator:
                instance_code = instance.code
                self[instance_code] = instance
                if instance_code == code:
                    return instance
        return default

class AttributesQuerysetCache:

    def __init__(self, product):
        self.product = product

    @cached_property
    def attributes(self):
        return QuerysetCache(self.product.get_product_class().attributes.all())

    @cached_property
    def attribute_values(self):
        if hasattr(self.product, '_prefetched_attribute_values'):
            return QuerysetCache(self.product.get_attribute_values())
        return QuerysetCache(self.product.get_attribute_values().select_related('attribute').annotate(code=models.F('attribute__code')))

    def set_attributes(self, attributes):
        self.__dict__['attributes'] = attributes

class ProductAttributesContainer:
    """
    Stolen liberally from django-eav, but simplified to be product-specific

    To set attributes on a product, use the `attr` attribute:

        product.attr.weight = 125

    To refetch the attribute values from the database:

        product.attr.refresh()
    """
    RESERVED_ATTRIBUTES = {'_cache', '_dirty', 'initialized', '_initialized', '_product', 'get_all_attributes', 'get_attribute_by_code', 'get_value_by_attribute', 'get_values', 'initialize', 'product', 'refresh', 'prepare_save', 'save', 'set', 'update', 'validate_attributes'}

    def __init__(self, product):
        self.__dict__.update({'_product': product, '_initialized': False, '_dirty': set(), '_cache': None})

    def __deepcopy__(self, memo):
        cpy = ProductAttributesContainer(self.product)
        memo[id(self)] = cpy
        if self.initialized:
            for key, value in self.__dict__.items():
                if key != '_cache':
                    cpy.__dict__[key] = deepcopy(value, memo)
        return cpy

    def __getstate__(self):
        d = {}
        d.update(self.__dict__)
        d['_cache'] = None
        return d

    def __setstate__(self, d):
        self.__dict__.update(d)

    @property
    def product(self):
        return self._product

    @property
    def initialized(self):
        return self._initialized

    @property
    def cache(self):
        if self.__dict__['_cache'] is None:
            self.__dict__['_cache'] = AttributesQuerysetCache(self.product)
        return self.__dict__['_cache']

    def initialize(self):
        self.__dict__['_initialized'] = True
        attrs = self.__dict__
        for v in self.get_values():
            attrs.setdefault(v.attribute.code, v.value)

    def invalidate(self):
        """Invalidate any stored data, queried from the database"""
        self.__dict__['_cache'] = None
        self.__dict__['_initialized'] = False

    def refresh(self):
        """Reload any queried data from the database, discarding local changes"""
        self.__dict__['_cache'] = None
        for v in self.get_values():
            setattr(self, v.attribute.code, v.value)

    def __getattribute__(self, name):
        try:
            return super().__getattribute__(name)
        except AttributeError:
            if self.initialized:
                raise
            else:
                self.initialize()
                return super().__getattribute__(name)

    def __getattr__(self, name):
        raise AttributeError(_("%(obj)s has no attribute named '%(attr)s'") % {'obj': self.product.get_product_class(), 'attr': name})

    def __setattr__(self, name, value):
        if name in self.RESERVED_ATTRIBUTES:
            raise ValidationError('%s is a reserved name and cannot be used as an attribute' % name)
        self._dirty.add(name)
        super().__setattr__(name, value)

    def set(self, name, value, validate_identifier=True):
        if not validate_identifier or name.isidentifier():
            self.__setattr__(name, value)
        else:
            raise ValidationError(_('%s is not a valid identifier, but attribute codes must be valid python identifiers' % name))

    def update(self, adict):
        self._dirty.update(adict.keys())
        self.__dict__.update(adict)

    def validate_attributes(self):
        for attribute in self.get_all_attributes():
            value = getattr(self, attribute.code, None)
            if value is None:
                if attribute.required:
                    raise ValidationError(_('%(attr)s attribute cannot be blank') % {'attr': attribute.code})
            else:
                try:
                    attribute.validate_value(value)
                except ValidationError as e:
                    raise ValidationError(_('%(attr)s attribute %(err)s') % {'attr': attribute.code, 'err': e})

    def get_values(self):
        return self.cache.attribute_values.queryset()

    def get_value_by_attribute(self, attribute):
        return self.cache.attribute_values.get(attribute.code)

    def get_all_attributes(self):
        return self.cache.attributes.queryset()

    def get_attribute_by_code(self, code):
        return self.cache.attributes.get(code)

    def __iter__(self):
        return iter(self.get_values())

    def prepare_save(self):
        to_be_updated = []
        to_be_created = []
        to_be_deleted = []
        update_fields = set()
        if not self.initialized and (not self._dirty):
            return (to_be_updated, to_be_created, to_be_deleted, update_fields)
        ProductAttributeValue = self.product.attribute_values.model
        for attribute in self.get_all_attributes():
            if hasattr(self, attribute.code):
                value = getattr(self, attribute.code)
                if attribute.code not in self._dirty:
                    try:
                        attribute_value_current = self.get_value_by_attribute(attribute)
                        if attribute_value_current is not None and attribute_value_current.value == value:
                            continue
                    except ObjectDoesNotExist:
                        pass
                if attribute.is_multi_option:
                    attribute.save_value(self.product, value)
                else:
                    value_obj = self.get_value_by_attribute(attribute)
                    if value_obj is None or value_obj.product != self.product:
                        new_value_obj = ProductAttributeValue(attribute=attribute, product=self.product)
                        bound_value_obj = attribute.bind_value(new_value_obj, value)
                        if bound_value_obj is not None and bound_value_obj.is_dirty:
                            assert not bound_value_obj.pk
                            to_be_created.append(bound_value_obj)
                    else:
                        bound_value_obj = attribute.bind_value(value_obj, value)
                        if bound_value_obj is None:
                            to_be_deleted.append(value_obj.pk)
                        else:
                            if bound_value_obj.attribute.is_entity:
                                bound_value_obj.save()
                                continue
                            if bound_value_obj.attribute.is_file:
                                bound_value_obj._meta.get_field(bound_value_obj.value_field_name).pre_save(bound_value_obj, False)
                            if bound_value_obj.attribute_id != attribute.id:
                                bound_value_obj.attribute = attribute
                                update_fields.add('attribute')
                            to_be_updated.append(bound_value_obj)
                            update_fields.add(bound_value_obj.value_field_name)
        return (to_be_updated, to_be_created, to_be_deleted, update_fields)

    def save(self):
        to_be_updated, to_be_created, to_be_deleted, update_fields = self.prepare_save()
        if to_be_deleted:
            self.product.attribute_values.filter(pk__in=to_be_deleted).delete()
        if to_be_updated:
            self.product.attribute_values.bulk_update(to_be_updated, update_fields, batch_size=500)
        if to_be_created:
            self.product.attribute_values.bulk_create(to_be_created, batch_size=500, ignore_conflicts=False)
        self.invalidate()

class Importer(object):
    allowed_extensions = ['.jpeg', '.jpg', '.gif', '.png']

    def __init__(self, logger, field):
        self.logger = logger
        self._field = field

    @atomic
    def handle(self, dirname):
        stats = {'num_processed': 0, 'num_skipped': 0, 'num_invalid': 0}
        image_dir, filenames = self._get_image_files(dirname)
        if image_dir:
            for filename in filenames:
                try:
                    lookup_value = self._get_lookup_value_from_filename(filename)
                    self._process_image(image_dir, filename, lookup_value)
                    stats['num_processed'] += 1
                except Product.MultipleObjectsReturned:
                    self.logger.warning("Multiple products matching %s='%s', skipping" % (self._field, lookup_value))
                    stats['num_skipped'] += 1
                except Product.DoesNotExist:
                    self.logger.warning("No item matching %s='%s'" % (self._field, lookup_value))
                    stats['num_skipped'] += 1
                except IdenticalImageError:
                    self.logger.warning("Identical image already exists for %s='%s', skipping" % (self._field, lookup_value))
                    stats['num_skipped'] += 1
                except IOError as e:
                    stats['num_invalid'] += 1
                    raise ImageImportError(_('%(filename)s is not a valid image (%(error)s)') % {'filename': filename, 'error': e})
                except FieldError as e:
                    raise ImageImportError(e)
            if image_dir != dirname:
                shutil.rmtree(image_dir)
        else:
            raise InvalidImageArchive(_('%s is not a valid image archive') % dirname)
        self.logger.info('Finished image import: %(num_processed)d imported, %(num_skipped)d skipped' % stats)

    def _get_image_files(self, dirname):
        filenames = []
        image_dir = self._extract_images(dirname)
        if image_dir:
            for filename in os.listdir(image_dir):
                ext = os.path.splitext(filename)[1]
                if os.path.isfile(os.path.join(image_dir, filename)) and ext in self.allowed_extensions:
                    filenames.append(filename)
        return (image_dir, filenames)

    def _extract_images(self, dirname):
        """
        Returns path to directory containing images in dirname if successful.
        Returns empty string if dirname does not exist, or could not be opened.
        Assumes that if dirname is a directory, then it contains images.
        If dirname is an archive (tar/zip file) then the path returned is to a
        temporary directory that should be deleted when no longer required.
        """
        if os.path.isdir(dirname):
            return dirname
        ext = os.path.splitext(dirname)[1]
        if ext in ['.gz', '.tar']:
            image_dir = tempfile.mkdtemp()
            try:
                tar_file = tarfile.open(dirname)
                tar_file.extractall(image_dir)
                tar_file.close()
                return image_dir
            except (tarfile.TarError, zlib.error):
                return ''
        elif ext == '.zip':
            image_dir = tempfile.mkdtemp()
            try:
                zip_file = zipfile.ZipFile(dirname)
                zip_file.extractall(image_dir)
                zip_file.close()
                return image_dir
            except (zlib.error, zipfile.BadZipfile, zipfile.LargeZipFile):
                return ''
        return ''

    def _process_image(self, dirname, filename, lookup_value):
        file_path = os.path.join(dirname, filename)
        trial_image = Image.open(file_path)
        trial_image.verify()
        kwargs = {self._field: lookup_value}
        item = Product._default_manager.get(**kwargs)
        new_data = open(file_path, 'rb').read()
        next_index = 0
        for existing in item.images.all():
            next_index = existing.display_order + 1
            try:
                if new_data == existing.original.read():
                    raise IdenticalImageError()
            except IOError:
                existing.delete()
        new_file = File(open(file_path, 'rb'))
        im = ProductImage(product=item, display_order=next_index)
        im.original.save(filename, new_file, save=False)
        im.save()
        self.logger.debug('Image added to "%s"' % item)

    def _fetch_item(self, filename):
        kwargs = {self._field: self._get_lookup_value_from_filename(filename)}
        return Product._default_manager.get(**kwargs)

    def _get_lookup_value_from_filename(self, filename):
        return os.path.splitext(filename)[0]

class ProductDetailView(DetailView):
    context_object_name = 'product'
    model = Product
    view_signal = product_viewed
    template_folder = 'catalogue'
    enforce_paths = True
    enforce_parent = False

    def get(self, request, *args, **kwargs):
        """
        Ensures that the correct URL is used before rendering a response
        """
        self.object = product = self.get_object()
        if (redirect_to := self.redirect_if_necessary(request.path, product)):
            return redirect_to
        if not self.is_viewable(product, request):
            raise Http404()
        response = super().get(request, *args, **kwargs)
        self.send_signal(request, response, product)
        return response

    def is_viewable(self, product, request):
        if product.is_child:
            return product.is_public and product.parent.is_public or request.user.is_staff
        return product.is_public or request.user.is_staff

    def get_object(self, queryset=None):
        if hasattr(self, 'object'):
            return self.object
        else:
            return super().get_object(queryset)

    def redirect_if_necessary(self, current_path, product):
        if self.enforce_parent and product.is_child:
            return HttpResponsePermanentRedirect(product.parent.get_absolute_url())
        if self.enforce_paths:
            expected_path = product.get_absolute_url()
            if quote(expected_path) != quote(current_path):
                return HttpResponsePermanentRedirect(expected_path)

    def get_context_data(self, **kwargs):
        ctx = super().get_context_data(**kwargs)
        ctx['alert_form'] = self.get_alert_form()
        ctx['has_active_alert'] = self.get_alert_status()
        return ctx

    def get_alert_status(self):
        has_alert = False
        if self.request.user.is_authenticated:
            alerts = ProductAlert.objects.filter(product=self.object, user=self.request.user, status=ProductAlert.ACTIVE)
            has_alert = alerts.exists()
        return has_alert

    def get_alert_form(self):
        return ProductAlertForm(user=self.request.user, product=self.object)

    def send_signal(self, request, response, product):
        self.view_signal.send(sender=self, product=product, user=request.user, request=request, response=response)

    def get_template_names(self):
        """
        Return a list of possible templates.

        If an overriding class sets a template name, we use that. Otherwise,
        we try 2 options before defaulting to :file:`catalogue/detail.html`:

            1. :file:`detail-for-upc-{upc}.html`
            2. :file:`detail-for-class-{classname}.html`

        This allows alternative templates to be provided for a per-product
        and a per-item-class basis.
        """
        if self.template_name:
            return [self.template_name]
        return ['oscar/%s/detail-for-upc-%s.html' % (self.template_folder, self.object.upc), 'oscar/%s/detail-for-class-%s.html' % (self.template_folder, self.object.get_product_class().slug), 'oscar/%s/detail.html' % self.template_folder]

