            return _("Email to %(email)s with subject '%(subject)s'") % {'email': self.email, 'subject': self.subject}

class CommunicationTypeManager(models.Manager):

    def get_and_render(self, code, context):
        """
        Return a dictionary of rendered messages, ready for sending.

        This method wraps around whether an instance of this event-type exists
        in the database.  If not, then an instance is created on the fly and
        used to generate the message contents.
        """
        try:
            commtype = self.get(code=code)
        except self.model.DoesNotExist:
            commtype = self.model(code=code)
        return commtype.get_messages(context)

class Dispatcher(object):

    def __init__(self, logger=None, mail_connection=None):
        if not logger:
            logger = logging.getLogger(__name__)
        self.logger = logger
        self.mail_connection = mail_connection

    def dispatch_direct_messages(self, recipient_email, messages, attachments=None):
        """
        Dispatch one-off messages to explicitly specified recipient email.
        """
        if messages['subject'] and (messages['body'] or messages['html']):
            return self.send_email_messages(recipient_email, messages, attachments=attachments)

    def dispatch_anonymous_messages(self, email, messages, attachments=None):
        dispatched_messages = {}
        if email:
            dispatched_messages['email'] = (self.send_email_messages(email, messages, attachments=attachments), None)
        return dispatched_messages

    def dispatch_user_messages(self, user, messages, attachments=None):
        """
        Send messages to a site user
        """
        dispatched_messages = {}
        if messages['subject'] and (messages['body'] or messages['html']):
            dispatched_messages['email'] = self.send_user_email_messages(user, messages, attachments)
        if messages['sms']:
            dispatched_messages['sms'] = self.send_text_message(user, messages['sms'])
        return dispatched_messages

    def notify_user(self, user, subject, **kwargs):
        """
        Send a simple notification to a user
        """
        Notification.objects.create(recipient=user, subject=subject, **kwargs)

    def notify_users(self, users, subject, **kwargs):
        """
        Send a simple notification to an iterable of users
        """
        for user in users:
            self.notify_user(user, subject, **kwargs)

    def create_email(self, user, messages, email):
        """
        Create ``Email`` instance in database for logging purposes.
        """
        if email and user.is_authenticated:
            return Email.objects.create(user=user, email=user.email, subject=email.subject, body_text=email.body, body_html=messages['html'])

    def send_user_email_messages(self, user, messages, attachments=None):
        """
        Send message to the registered user / customer and collect data in database.
        """
        if not user.email:
            self.logger.warning('Unable to send email messages as user #%d has no email address', user.id)
            return None
        email = self.send_email_messages(user.email, messages, attachments=attachments)
        if settings.OSCAR_SAVE_SENT_EMAILS_TO_DB:
            self.create_email(user, messages, email)
        return email

    def send_email_messages(self, recipient_email, messages, from_email=None, attachments=None):
        """
        Send email to recipient, HTML attachment optional.
        """
        from_email = from_email or settings.OSCAR_FROM_EMAIL
        content_attachments, file_attachments = self.prepare_attachments(attachments)
        if messages['html']:
            email = EmailMultiAlternatives(messages['subject'], messages['body'], from_email=from_email, to=[recipient_email], attachments=content_attachments)
            email.attach_alternative(messages['html'], 'text/html')
        else:
            email = EmailMessage(messages['subject'], messages['body'], from_email=from_email, to=[recipient_email], attachments=content_attachments)
        for attachment in file_attachments:
            email.attach_file(attachment)
        self.logger.info('Sending email to %s', recipient_email)
        if self.mail_connection:
            self.mail_connection.send_messages([email])
        else:
            email.send()
        return email

    def send_text_message(self, user, event_type):
        raise NotImplementedError

    def prepare_attachments(self, attachments):
        """
        Two types of attachments can be attached to emails:

            * "Content" attachment is one of:
                * instance of ``MIMEBase`` (from ``email.mime.base``);
                * list ``[filename, content, mimetype]``;

            * "File" attachment is a path to file from an instance of
              ``FileField`` based fields.

        "Content" and "file" attachments attached to emails differently.
        """
        content_attachments = []
        file_attachments = []
        if attachments is not None:
            for attachment in attachments:
                if isinstance(attachment, str):
                    file_attachments.append(attachment)
                else:
                    content_attachments.append(attachment)
        return (content_attachments, file_attachments)

    def get_base_context(self, **kwargs):
        """
        Return context that is common to all emails
        """
        request = kwargs.get('request')
        return dict(kwargs, site=Site.objects.get_current(request))

    def get_messages(self, event_code, extra_context=None):
        """
        Return rendered messages
        """
        if extra_context is None:
            extra_context = {}
        context = self.get_base_context(**extra_context)
        msgs = CommunicationEventType.objects.get_and_render(event_code, context)
        return msgs

class AbstractProductAlert(models.Model):
    """
    An alert for when a product comes back in stock
    """
    product = models.ForeignKey('catalogue.Product', on_delete=models.CASCADE)
    user = models.ForeignKey(AUTH_USER_MODEL, blank=True, null=True, on_delete=models.CASCADE, related_name='alerts', verbose_name=_('User'))
    email = models.EmailField(_('Email'), db_index=True, blank=True)
    key = models.CharField(_('Key'), max_length=128, blank=True, db_index=True)
    UNCONFIRMED, ACTIVE, CANCELLED, CLOSED = ('Unconfirmed', 'Active', 'Cancelled', 'Closed')
    STATUS_CHOICES = ((UNCONFIRMED, _('Not yet confirmed')), (ACTIVE, _('Active')), (CANCELLED, _('Cancelled')), (CLOSED, _('Closed')))
    status = models.CharField(_('Status'), max_length=20, choices=STATUS_CHOICES, default=ACTIVE)
    date_created = models.DateTimeField(_('Date created'), auto_now_add=True, db_index=True)
    date_confirmed = models.DateTimeField(_('Date confirmed'), blank=True, null=True)
    date_cancelled = models.DateTimeField(_('Date cancelled'), blank=True, null=True)
    date_closed = models.DateTimeField(_('Date closed'), blank=True, null=True)

    class Meta:
        abstract = True
        app_label = 'customer'
        ordering = ['-date_created']
        verbose_name = _('Product alert')
        verbose_name_plural = _('Product alerts')

    @property
    def is_anonymous(self):
        return self.user is None

    @property
    def can_be_confirmed(self):
        return self.status == self.UNCONFIRMED

    @property
    def can_be_cancelled(self):
        return self.status in (self.ACTIVE, self.UNCONFIRMED)

    @property
    def is_cancelled(self):
        return self.status == self.CANCELLED

    @property
    def is_active(self):
        return self.status == self.ACTIVE

    def confirm(self):
        self.status = self.ACTIVE
        self.date_confirmed = timezone.now()
        self.save()
    confirm.alters_data = True

    def cancel(self):
        self.status = self.CANCELLED
        self.date_cancelled = timezone.now()
        self.save()
    cancel.alters_data = True

    def close(self):
        self.status = self.CLOSED
        self.date_closed = timezone.now()
        self.save()
    close.alters_data = True

    def get_email_address(self):
        if self.user:
            return self.user.email
        else:
            return self.email

    def save(self, *args, **kwargs):
        if not self.id and (not self.user):
            self.key = self.get_random_key()
            self.status = self.UNCONFIRMED
        if self.status == self.CANCELLED and self.date_cancelled is None:
            self.date_cancelled = timezone.now()
        if not self.user and self.status == self.ACTIVE and (self.date_confirmed is None):
            self.date_confirmed = timezone.now()
        if self.status == self.CLOSED and self.date_closed is None:
            self.date_closed = timezone.now()
        return super().save(*args, **kwargs)

    def get_random_key(self):
        return get_random_string(length=40, allowed_chars='abcdefghijklmnopqrstuvwxyz0123456789')

    def get_confirm_url(self):
        return reverse('customer:alerts-confirm', kwargs={'key': self.key})

    def get_cancel_url(self):
        return reverse('customer:alerts-cancel-by-key', kwargs={'key': self.key})

class EmailBackend(ModelBackend):
    """
    Custom auth backend that uses an email address and password

    For this to work, the User model must have an 'email' field
    """

    def _authenticate(self, request, email=None, password=None, *args, **kwargs):
        if email is None:
            if 'username' not in kwargs or kwargs['username'] is None:
                return None
            clean_email = normalise_email(kwargs['username'])
        else:
            clean_email = normalise_email(email)
        if '@' not in clean_email:
            return None
        matching_users = User.objects.filter(email__iexact=clean_email)
        authenticated_users = [user for user in matching_users if user.check_password(password) and self.user_can_authenticate(user)]
        if len(authenticated_users) == 1:
            return authenticated_users[0]
        elif len(authenticated_users) > 1:
            raise User.MultipleObjectsReturned('There are multiple users with the given email address and password')
        return None

    def authenticate(self, *args, **kwargs):
        return self._authenticate(*args, **kwargs)

class PasswordResetForm(auth_forms.PasswordResetForm):
    """
    This form takes the same structure as its parent from :py:mod:`django.contrib.auth`
    """

    def save(self, *args, domain_override=None, request=None, **kwargs):
        """
        Generates a one-use only link for resetting password and sends to the
        user.
        """
        site = get_current_site(request)
        if domain_override is not None:
            site.domain = site.name = domain_override
        for user in self.get_users(self.cleaned_data['email']):
            self.send_password_reset_email(site, user, request)

    def send_password_reset_email(self, site, user, request=None):
        extra_context = {'user': user, 'site': site, 'reset_url': get_password_reset_url(user), 'request': request}
        CustomerDispatcher().send_password_reset_email_for_user(user, extra_context)

class EmailUserCreationForm(forms.ModelForm):
    email = forms.EmailField(label=_('Email address'))
    password1 = forms.CharField(label=_('Password'), widget=forms.PasswordInput)
    password2 = forms.CharField(label=_('Confirm password'), widget=forms.PasswordInput)
    redirect_url = forms.CharField(widget=forms.HiddenInput, required=False)

    class Meta:
        model = User
        fields = ('email',)

    def __init__(self, *args, host=None, **kwargs):
        self.host = host
        super().__init__(*args, **kwargs)

    def _post_clean(self):
        super()._post_clean()
        password = self.cleaned_data.get('password2')
        if password:
            try:
                validate_password(password, self.instance)
            except forms.ValidationError as error:
                self.add_error('password2', error)

    def clean_email(self):
        """
        Checks for existing users with the supplied email address.
        """
        email = normalise_email(self.cleaned_data['email'])
        if User._default_manager.filter(email__iexact=email).exists():
            raise forms.ValidationError(_('A user with that email address already exists'))
        return email

    def clean_password2(self):
        password1 = self.cleaned_data.get('password1', '')
        password2 = self.cleaned_data.get('password2', '')
        if password1 != password2:
            raise forms.ValidationError(_("The two password fields didn't match."))
        return password2

    def clean_redirect_url(self):
        url = self.cleaned_data['redirect_url'].strip()
        if not url or not url_has_allowed_host_and_scheme(url, self.host):
            return settings.LOGIN_REDIRECT_URL
        try:
            parsed = urlparse(url)
            resolve(parsed.path)
        except Resolver404:
            return settings.LOGIN_REDIRECT_URL
        return url

    def save(self, commit=True):
        user = super().save(commit=False)
        user.set_password(self.cleaned_data['password1'])
        if 'username' in [f.name for f in User._meta.fields]:
            user.username = generate_username()
        if commit:
            user.save()
        return user

class OrderSearchForm(forms.Form):
    date_from = forms.DateField(required=False, label=pgettext_lazy('start date', 'From'), widget=widgets.DatePickerInput())
    date_to = forms.DateField(required=False, label=pgettext_lazy('end date', 'To'), widget=widgets.DatePickerInput())
    order_number = forms.CharField(required=False, label=_('Order number'))

    def clean(self):
        if self.is_valid() and (not any([self.cleaned_data['date_from'], self.cleaned_data['date_to'], self.cleaned_data['order_number']])):
            raise forms.ValidationError(_('At least one field is required.'))
        return super().clean()

    def description(self):
        """
        Uses the form's data to build a useful description of what orders
        are listed.
        """
        if not self.is_bound or not self.is_valid():
            return _('All orders')
        else:
            date_from = self.cleaned_data['date_from']
            date_to = self.cleaned_data['date_to']
            order_number = self.cleaned_data['order_number']
            return self._orders_description(date_from, date_to, order_number)

    def _orders_description(self, date_from, date_to, order_number):
        if date_from and date_to:
            if order_number:
                desc = _('Orders placed between %(date_from)s and %(date_to)s and order number containing %(order_number)s')
            else:
                desc = _('Orders placed between %(date_from)s and %(date_to)s')
        elif date_from:
            if order_number:
                desc = _('Orders placed since %(date_from)s and order number containing %(order_number)s')
            else:
                desc = _('Orders placed since %(date_from)s')
        elif date_to:
            if order_number:
                desc = _('Orders placed until %(date_to)s and order number containing %(order_number)s')
            else:
                desc = _('Orders placed until %(date_to)s')
        elif order_number:
            desc = _('Orders with order number containing %(order_number)s')
        else:
            return None
        params = {'date_from': date_from, 'date_to': date_to, 'order_number': order_number}
        return desc % params

    def get_filters(self):
        date_from = self.cleaned_data['date_from']
        date_to = self.cleaned_data['date_to']
        order_number = self.cleaned_data['order_number']
        kwargs = {}
        if date_from:
            kwargs['date_placed__gte'] = datetime_combine(date_from, datetime.time.min)
        if date_to:
            kwargs['date_placed__lte'] = datetime_combine(date_to, datetime.time.max)
        if order_number:
            kwargs['number__contains'] = order_number
        return kwargs

class ProductAlertForm(forms.ModelForm):
    email = forms.EmailField(required=True, label=_('Send notification to'), widget=forms.TextInput(attrs={'placeholder': _('Enter your email')}))

    def __init__(self, user, product, *args, **kwargs):
        self.user = user
        self.product = product
        super().__init__(*args, **kwargs)
        if user and user.is_authenticated:
            self.fields['email'].widget = forms.HiddenInput()
            self.fields['email'].required = False

    def save(self, commit=True):
        alert = super().save(commit=False)
        if self.user.is_authenticated:
            alert.user = self.user
        alert.product = self.product
        if commit:
            alert.save()
        return alert

    def clean(self):
        cleaned_data = self.cleaned_data
        email = cleaned_data.get('email')
        if email:
            try:
                ProductAlert.objects.get(product=self.product, email__iexact=email, status=ProductAlert.ACTIVE)
            except ProductAlert.DoesNotExist:
                pass
            else:
                raise forms.ValidationError(_('There is already an active stock alert for %s') % email)
            if ProductAlert.objects.filter(email__iexact=email, status=ProductAlert.UNCONFIRMED).count():
                raise forms.ValidationError(_('%s has been sent a confirmation email for another product alert on this site. Please confirm or cancel that request before signing up for more alerts.') % email)
        elif self.user.is_authenticated:
            try:
                ProductAlert.objects.get(product=self.product, user=self.user, status=ProductAlert.ACTIVE)
            except ProductAlert.DoesNotExist:
                pass
            else:
                raise forms.ValidationError(_('You already have an active alert for this product'))
        return cleaned_data

    class Meta:
        model = ProductAlert
        fields = ['email']

