class CustomerHistoryManager:
    cookie_name = settings.OSCAR_RECENTLY_VIEWED_COOKIE_NAME
    cookie_kwargs = {'max_age': settings.OSCAR_RECENTLY_VIEWED_COOKIE_LIFETIME, 'secure': settings.OSCAR_RECENTLY_VIEWED_COOKIE_SECURE, 'httponly': True, 'samesite': settings.SESSION_COOKIE_SAMESITE}
    max_products = settings.OSCAR_RECENTLY_VIEWED_PRODUCTS

    @classmethod
    def get(cls, request):
        """
        Return a list of recently viewed products
        """
        ids = cls.extract(request)
        product_dict = Product.objects.browsable().in_bulk(ids)
        ids.reverse()
        return [product_dict[product_id] for product_id in ids if product_id in product_dict]

    @classmethod
    def extract(cls, request, response=None):
        """
        Extract the IDs of products in the history cookie
        """
        ids = []
        if cls.cookie_name in request.COOKIES:
            try:
                ids = json.loads(request.COOKIES[cls.cookie_name])
            except ValueError:
                if response:
                    response.delete_cookie(cls.cookie_name)
            else:
                if not isinstance(ids, list):
                    ids = []
        return ids

    @classmethod
    def add(cls, ids, new_id):
        """
        Add a new product ID to the list of product IDs
        """
        if new_id in ids:
            ids.remove(new_id)
        ids.append(new_id)
        if len(ids) > cls.max_products:
            ids = ids[len(ids) - cls.max_products:]
        return ids

    @classmethod
    def update(cls, product, request, response):
        """
        Updates the cookies that store the recently viewed products
        removing possible duplicates.
        """
        ids = cls.extract(request, response)
        updated_ids = cls.add(ids, product.id)
        response.set_cookie(cls.cookie_name, json.dumps(updated_ids), **cls.cookie_kwargs)

class RegisterUserMixin(object):

    def register_user(self, form):
        """
        Create a user instance and send a new registration email (if configured
        to).
        """
        user = form.save()
        user_registered.send_robust(sender=self, request=self.request, user=user)
        if getattr(settings, 'OSCAR_SEND_REGISTRATION_EMAIL', True):
            self.send_registration_email(user)
        try:
            user = authenticate(username=user.email, password=form.cleaned_data['password1'])
        except User.MultipleObjectsReturned:
            logger.warning('Multiple users with identical email address and passwordwere found. Marking all but one as not active.')
            users = User.objects.filter(email=user.email)
            user = users[0]
            user.backend = 'oscar.apps.customer.auth_backends.EmailBackend'
            for u in users[1:]:
                u.is_active = False
                u.save()
        auth_login(self.request, user)
        return user

    def send_registration_email(self, user):
        extra_context = {'user': user, 'request': self.request}
        CustomerDispatcher().send_registration_email_for_user(user, extra_context)

class AnonymousOrderMixin:

    @property
    def email(self):
        return self.request.session.get('anon_order_email')

    @property
    def order_number(self):
        return self.kwargs.get('order_number')

    @property
    def hash(self):
        return self.kwargs.get('hash')

    def get_object(self):
        try:
            order = Order.objects.get(user=None, number=self.order_number)
            if order.check_verification_hash(self.hash) and order.email == self.email:
                return order
        except (AttributeError, Order.DoesNotExist):
            return None
        return None

class AccountRegistrationView(RegisterUserMixin, generic.FormView):
    form_class = EmailUserCreationForm
    template_name = 'oscar/customer/registration.html'
    redirect_field_name = 'next'

    def get(self, request, *args, **kwargs):
        if request.user.is_authenticated:
            return redirect(settings.LOGIN_REDIRECT_URL)
        return super().get(request, *args, **kwargs)

    def get_logged_in_redirect(self):
        return reverse('customer:summary')

    def get_form_kwargs(self):
        kwargs = super().get_form_kwargs()
        kwargs['initial'] = {'email': self.request.GET.get('email', ''), 'redirect_url': self.request.GET.get(self.redirect_field_name, '')}
        kwargs['host'] = self.request.get_host()
        return kwargs

    def get_context_data(self, *args, **kwargs):
        ctx = super().get_context_data(*args, **kwargs)
        ctx['cancel_url'] = safe_referrer(self.request, '')
