class OrderDetailView(PageTitleMixin, PostActionMixin, generic.DetailView):
    model = Order
    active_tab = 'orders'

    def get_template_names(self):
        return ['oscar/customer/order/order_detail.html']

    def get_page_title(self):
        """
        Order number as page title
        """
        return '%s #%s' % (_('Order'), self.object.number)

    def get_object(self, queryset=None):
        return get_object_or_404(self.model, user=self.request.user, number=self.kwargs['order_number'])

    def do_reorder(self, order):
        """
        'Re-order' a previous order.

        This puts the contents of the previous order into your basket
        """
        basket = self.request.basket
        lines_to_add = []
        warnings = []
        for line in order.lines.all():
            is_available, reason = line.is_available_to_reorder(basket, self.request.strategy)
            if is_available:
                lines_to_add.append(line)
            else:
                warnings.append(reason)
        total_quantity = sum([line.quantity for line in lines_to_add])
        is_quantity_allowed, reason = basket.is_quantity_allowed(total_quantity)
        if not is_quantity_allowed:
            messages.warning(self.request, reason)
            self.response = redirect('customer:order-list')
            return
        for warning in warnings:
            messages.warning(self.request, warning)
        for line in lines_to_add:
            options = []
            for attribute in line.attributes.all():
                if attribute.option:
                    options.append({'option': attribute.option, 'value': attribute.value})
            basket.add_product(line.product, line.quantity, options)
        if len(lines_to_add) > 0:
            self.response = redirect('basket:summary')
            messages.info(self.request, _('All available lines from order %(number)s have been added to your basket') % {'number': order.number})
        else:
            self.response = redirect('customer:order-list')
            messages.warning(self.request, _('It is not possible to re-order order %(number)s as none of its lines are available to purchase') % {'number': order.number})

class OrderLineView(PostActionMixin, generic.DetailView):
    """Customer order line"""

    def get_object(self, queryset=None):
        order = get_object_or_404(Order, user=self.request.user, number=self.kwargs['order_number'])
        return order.lines.get(id=self.kwargs['line_id'])

    def do_reorder(self, line):
        self.response = redirect('customer:order', self.kwargs['order_number'])
        basket = self.request.basket
        line_available_to_reorder, reason = line.is_available_to_reorder(basket, self.request.strategy)
        if not line_available_to_reorder:
            messages.warning(self.request, reason)
            return
        self.response = redirect('basket:summary')
        options = []
        for attribute in line.attributes.all():
            if attribute.option:
                options.append({'option': attribute.option, 'value': attribute.value})
        basket.add_product(line.product, line.quantity, options)
        if line.quantity > 1:
            msg = _("%(qty)d copies of '%(product)s' have been added to your basket") % {'qty': line.quantity, 'product': line.product}
        else:
            msg = _("'%s' has been added to your basket") % line.product
        messages.info(self.request, msg)

