class Node(object):
    """
    A node in the dashboard navigation menu
    """

    def __init__(self, label, url_name=None, url_args=None, url_kwargs=None, access_fn=None, icon=None):
        self.label = label
        self.icon = icon
        self.url_name = url_name
        self.url_args = url_args
        self.url_kwargs = url_kwargs
        self.access_fn = access_fn
        self.children = []

    @property
    def is_heading(self):
        return self.url_name is None

    @property
    def url(self):
        return reverse(self.url_name, args=self.url_args, kwargs=self.url_kwargs)

    def add_child(self, node):
        self.children.append(node)

    def is_visible(self, user):
        return self.access_fn is None or self.access_fn(user, self.url_name, self.url_args, self.url_kwargs)

    def filter(self, user):
        if not self.is_visible(user):
            return None
        node = Node(label=self.label, url_name=self.url_name, url_args=self.url_args, url_kwargs=self.url_kwargs, access_fn=self.access_fn, icon=self.icon)
        for child in self.children:
            if child.is_visible(user):
                node.add_child(child)
        return node

    def has_children(self):
        return len(self.children) > 0

class DashboardPermission:
    """Permissions used for different dashboard views."""
    permissions = {}
    staff = ['is_staff']
    partner_dashboard_access = ['partner.dashboard_access']

    @classmethod
    def get(cls, app_label, *codenames):
        """
        Get permissions for given app_label and codenames.
        Supports both explicit mappings and auto-generated permissions.
        """
        permissions = set()
        for codename in codenames:
            key = codename
            if key in cls.permissions:
                permissions.update(cls.permissions[key])
            else:
                permissions.add(f'{app_label}.{codename}')
        return list(permissions)

