    max_global_applications = models.PositiveIntegerField(_('Max global applications'), help_text=_('The number of times this offer can be used before it is unavailable'), blank=True, null=True)
    max_user_applications = models.PositiveIntegerField(_('Max user applications'), help_text=_('The number of times a single user can use this offer'), blank=True, null=True)
    max_basket_applications = models.PositiveIntegerField(_('Max basket applications'), blank=True, null=True, help_text=_('The number of times this offer can be applied to a basket (and order)'))
