class RangeQuerySet(models.query.QuerySet):
    """
    This queryset add ``contains_product`` which allows selecting the
    ranges that contain the product in question.
    """

    def _excluded_products_clause(self, product):
        if product.structure == product.CHILD:
            return ~(models.Q(excluded_products=product) | models.Q(excluded_products__id=product.parent_id))
        return ~models.Q(excluded_products=product)

    def _excluded_categories_clause(self, product):
        if product.structure == product.CHILD:
            return ~models.Q(excluded_categories__id__in=product.parent.categories.values('id'))
        return ~models.Q(excluded_categories__id__in=product.categories.values('id'))

    def _included_products_clause(self, product):
        if product.structure == product.CHILD:
            return models.Q(included_products=product) | models.Q(included_products__id=product.parent_id)
        else:
            return models.Q(included_products=product)

    def _productclasses_clause(self, product):
        if product.structure == product.CHILD:
            return models.Q(classes__products__parent_id=product.parent_id)
        return models.Q(classes__id=product.product_class_id)

    def _get_category_ids(self, product):
        if product.structure == product.CHILD:
            ProductCategory = product.productcategory_set.model
            return ProductCategory.objects.filter(product_id=product.parent_id).values('category_id')
        return product.categories.values('id')

    def get_category_query(self, product):
        if use_productcategory_materialised_view():
            if product.structure == product.CHILD:
                return ProductCategoryHierarchy.objects.filter(product_id=product.parent_id).values_list('category_id')
            return ProductCategoryHierarchy.objects.filter(product_id=product.id).values_list('category_id')
        return ExpandUpwardsCategoryQueryset(self._get_category_ids(product))

    def contains_product(self, product):
        wide = self.filter(self._excluded_products_clause(product), self._excluded_categories_clause(product), includes_all_products=True)
        narrow = self.filter(self._excluded_products_clause(product), self._excluded_categories_clause(product), self._included_products_clause(product) | models.Q(included_categories__in=self.get_category_query(product)) | self._productclasses_clause(product), includes_all_products=False)
        return wide | narrow

