class BankcardExpiryMonthField(BankcardMonthField):
    num_years = 10

    def __init__(self, *args, **kwargs):
        today = date.today()
        _kwargs = {'required': True, 'label': _('Valid to'), 'initial': ['%.2d' % today.month, today.year]}
        _kwargs.update(kwargs)
        super().__init__(*args, **_kwargs)

    def month_choices(self):
        return [('%.2d' % x, '%.2d' % x) for x in range(1, 13)]

    def year_choices(self):
        return [(x, x) for x in range(date.today().year, date.today().year + self.num_years)]

    def clean(self, value):
        expiry_date = super().clean(value)
        if expiry_date and date.today() > expiry_date:
            raise forms.ValidationError(_('The expiration date you entered is in the past.'))
        return expiry_date

    def compress(self, data_list):
        if data_list:
            if data_list[1] in validators.EMPTY_VALUES:
                error = self.error_messages['invalid_year']
                raise forms.ValidationError(error)
            if data_list[0] in validators.EMPTY_VALUES:
                error = self.error_messages['invalid_month']
                raise forms.ValidationError(error)
            year = int(data_list[1])
            month = int(data_list[0])
            day = monthrange(year, month)[1]
            return date(year, month, day)
        return None

