class FacetMunger(object):

    def __init__(self, path, selected_multi_facets, facet_counts, query_type=None):
        self.base_url = URL(path)
        self.selected_facets = selected_multi_facets
        self.facet_counts = facet_counts
        self.query_type = query_type

    def facet_data(self):
        facet_data = {}
        if self.facet_counts:
            self.munge_field_facets(facet_data)
            if self.query_type is not None and self.query_type not in [WhooshSearchQuery]:
                self.munge_query_facets(facet_data)
        return facet_data

    def munge_field_facets(self, clean_data):
        for key, facet in settings.OSCAR_SEARCH_FACETS['fields'].items():
            self.munge_field_facet(key, facet, clean_data)

    def munge_field_facet(self, key, facet, clean_data):
        clean_data[key] = {'name': facet['name'], 'results': []}
        for field_value, count in self.facet_counts['fields'][key]:
            field_name = facet['field']
            is_faceted_already = field_name in self.selected_facets
            datum = {'name': field_value, 'count': count, 'show_count': not is_faceted_already, 'disabled': count == 0 and (not is_faceted_already), 'selected': False}
            if field_value in self.selected_facets.get(field_name, []):
                datum['selected'] = True
                url = self.base_url.remove_query_param('selected_facets', '%s:%s' % (field_name, field_value))
                datum['deselect_url'] = self.strip_pagination(url)
            else:
                url = self.base_url.append_query_param('selected_facets', '%s:%s' % (field_name, field_value))
                datum['select_url'] = self.strip_pagination(url)
            clean_data[key]['results'].append(datum)

    def munge_query_facets(self, clean_data):
        for key, facet in settings.OSCAR_SEARCH_FACETS['queries'].items():
            self.munge_query_facet(key, facet, clean_data)

    def munge_query_facet(self, key, facet, clean_data):
        clean_data[key] = {'name': facet['name'], 'results': []}
        for field_value, query in facet['queries']:
            field_name = facet['field']
            is_faceted_already = field_name in self.selected_facets
            match = '%s:%s' % (field_name, query)
            match_exact = f'{field_name}_exact:{query}' if is_solr_supported() else match
            if match_exact not in self.facet_counts['queries']:
                datum = {'name': field_value, 'count': 0, 'show_count': True, 'disabled': True}
            else:
                count = self.facet_counts['queries'][match_exact]
                datum = {'name': field_value, 'count': count, 'show_count': not is_faceted_already, 'disabled': count == 0 and (not is_faceted_already), 'selected': False}
                if query in self.selected_facets.get(field_name, []):
                    datum['selected'] = True
                    datum['show_count'] = True
                    url = self.base_url.remove_query_param('selected_facets', match)
                    datum['deselect_url'] = self.strip_pagination(url)
                else:
                    url = self.base_url.append_query_param('selected_facets', match)
                    datum['select_url'] = self.strip_pagination(url)
            clean_data[key]['results'].append(datum)

    def strip_pagination(self, url):
        if url.has_query_param('page'):
            url = url.remove_query_param('page')
        return url.as_string()

class SearchForm(FacetedSearchForm):
    """
    In Haystack, the search form is used for interpreting
    and sub-filtering the SQS.
    """
    q = forms.CharField(required=False, label=_('Search'), widget=SearchInput({'placeholder': _('Search'), 'tabindex': '1', 'class': 'form-control'}))
    RELEVANCY = 'relevancy'
    TOP_RATED = 'rating'
    NEWEST = 'newest'
    PRICE_HIGH_TO_LOW = 'price-desc'
    PRICE_LOW_TO_HIGH = 'price-asc'
    TITLE_A_TO_Z = 'title-asc'
    TITLE_Z_TO_A = 'title-desc'
    SORT_BY_CHOICES = [(RELEVANCY, _('Relevancy')), (TOP_RATED, _('Customer rating')), (NEWEST, _('Newest')), (PRICE_HIGH_TO_LOW, _('Price high to low')), (PRICE_LOW_TO_HIGH, _('Price low to high')), (TITLE_A_TO_Z, _('Title A to Z')), (TITLE_Z_TO_A, _('Title Z to A'))]
    SORT_BY_MAP = {TOP_RATED: '-rating', NEWEST: '-date_created', PRICE_HIGH_TO_LOW: '-price', PRICE_LOW_TO_HIGH: 'price', TITLE_A_TO_Z: 'title_s', TITLE_Z_TO_A: '-title_s'}
    if not is_solr_supported():
        SORT_BY_MAP[TITLE_A_TO_Z] = 'title_exact'
        SORT_BY_MAP[TITLE_Z_TO_A] = '-title_exact'
    sort_by = forms.ChoiceField(label=_('Sort by'), choices=SORT_BY_CHOICES, widget=forms.Select(), required=False)

    @property
    def selected_multi_facets(self):
        """
        Validate and return the selected facets
        """
        selected_multi_facets = defaultdict(list)
        for facet_kv in self.selected_facets:
            if ':' not in facet_kv:
                continue
            field_name, value = facet_kv.split(':', 1)
            if field_name in VALID_FACET_QUERIES:
                if value not in VALID_FACET_QUERIES[field_name]:
                    continue
            selected_multi_facets[field_name].append(value)
        return selected_multi_facets

    def search(self):
        sqs = super(FacetedSearchForm, self).search()
        for field, values in self.selected_multi_facets.items():
            if not values:
                continue
            if field in VALID_FACET_QUERIES:
                sqs = sqs.narrow('%s:(%s)' % (field, ' OR '.join(values)))
            else:
                clean_values = ['"%s"' % sqs.query.clean(val) for val in values]
                sqs = sqs.narrow('%s:(%s)' % (field, ' OR '.join(clean_values)))
        if self.is_valid() and 'sort_by' in self.cleaned_data:
            sort_field = self.SORT_BY_MAP.get(self.cleaned_data['sort_by'], None)
            if sort_field:
                sqs = sqs.order_by(sort_field)
        return sqs

