class TaxExclusiveOfferDiscount(OfferDiscount):
    """
    Wrapper class which extends OfferDiscount to be exclusive of tax.
    """

    def calculate(self, basket):
        base_charge = self.method.calculate(basket)
        discount = self.offer.shipping_discount(base_charge.excl_tax, base_charge.currency)
        excl_tax = base_charge.excl_tax - discount
        return prices.Price(currency=base_charge.currency, excl_tax=excl_tax, tax_code=base_charge.tax_code)

    def discount(self, basket):
        base_charge = self.method.calculate(basket)
        return self.offer.shipping_discount(base_charge.excl_tax, base_charge.currency)

class TaxInclusiveOfferDiscount(OfferDiscount):
    """
    Wrapper class which extends OfferDiscount to be inclusive of tax.
    """

    def calculate(self, basket):
        base_charge = self.method.calculate(basket)
        discount = self.offer.shipping_discount(base_charge.incl_tax, base_charge.currency)
        incl_tax = base_charge.incl_tax - discount
        excl_tax = self.calculate_excl_tax(base_charge, incl_tax)
        return prices.Price(currency=base_charge.currency, excl_tax=excl_tax, incl_tax=incl_tax, tax_code=base_charge.tax_code)

    def calculate_excl_tax(self, base_charge, incl_tax):
        """
        Return the charge excluding tax (but including discount).
        """
        if incl_tax == D('0.00'):
            return D('0.00')
        excl_tax = base_charge.excl_tax * (incl_tax / base_charge.incl_tax)
        return round_half_up_four_dec(excl_tax)

    def discount(self, basket):
        base_charge = self.method.calculate(basket)
        return self.offer.shipping_discount(base_charge.incl_tax, base_charge.currency)

class Scale(object):
    """
    For calculating the weight of a product or basket
    """

    def __init__(self, attribute_code='weight', default_weight=None):
        self.attribute = attribute_code
        self.default_weight = default_weight

    def weigh_product(self, product):
        weight = None
        try:
            weight = product.get_attribute_values().get(attribute__code=self.attribute).value
        except ObjectDoesNotExist:
            pass
        if weight is None:
            if self.default_weight is None:
                raise ValueError('No attribute %s found for product %s' % (self.attribute, product))
            weight = self.default_weight
        return D(weight) if weight is not None else D('0.0')

    def weigh_basket(self, basket):
        weight = D('0.0')
        for line in basket.all_lines():
            weight += self.weigh_product(line.product) * line.quantity
        return weight

