class AbstractWishList(models.Model):
    """
    Represents a user's wish lists of products.

    A user can have multiple wish lists, move products between them, etc.
    """
    owner = models.ForeignKey(AUTH_USER_MODEL, related_name='wishlists', on_delete=models.CASCADE, verbose_name=_('Owner'))
    name = models.CharField(verbose_name=_('Name'), default=_('Default'), max_length=255)
    key = models.CharField(_('Key'), max_length=6, db_index=True, unique=True, editable=False)
    PUBLIC, PRIVATE, SHARED = ('Public', 'Private', 'Shared')
    VISIBILITY_CHOICES = ((PRIVATE, _('Private - Only the owner can see the wish list')), (SHARED, _('Shared - Only the owner and people with access to the obfuscated link can see the wish list')), (PUBLIC, _('Public - Everybody can see the wish list')))
    visibility = models.CharField(_('Visibility'), max_length=20, default=PRIVATE, choices=VISIBILITY_CHOICES)
    date_created = models.DateTimeField(_('Date created'), auto_now_add=True, editable=False, db_index=True)

    def __str__(self):
        return "%s's Wish List '%s'" % (self.owner, self.name)

    def save(self, *args, **kwargs):
        if not self.pk or kwargs.get('force_insert', False):
            self.key = self.__class__.random_key()
        super().save(*args, **kwargs)

    @classmethod
    def random_key(cls, length=6):
        """
        Get a unique random generated key
        """
        while True:
            key = get_random_string(length=length, allowed_chars='abcdefghijklmnopqrstuvwxyz0123456789')
            if not cls._default_manager.filter(key=key).exists():
                return key

    def is_allowed_to_see(self, user):
        if user == self.owner:
            return True
        elif self.visibility == self.PUBLIC:
            return True
        elif self.visibility == self.SHARED and user.is_authenticated:
            return self.shared_emails.filter(email=user.email).exists()
        return False

    def is_allowed_to_edit(self, user):
        return user == self.owner

    class Meta:
        abstract = True
        app_label = 'wishlists'
        ordering = ('owner', 'date_created')
        verbose_name = _('Wish List')

    def get_absolute_url(self):
        return reverse('customer:wishlists-detail', kwargs={'key': self.key})

    def add(self, product):
        """
        Add a product to this wishlist
        """
        lines = self.lines.filter(product=product)
        if len(lines) == 0:
            self.lines.create(product=product, title=product.get_title())
        else:
            line = lines[0]
            line.quantity += 1
            line.save()

    def get_shared_url(self):
        return reverse('wishlists:detail', kwargs={'key': self.key})

    @property
    def is_shareable(self):
        return self.visibility in [self.PUBLIC, self.SHARED]

