class AbstractProductReview(models.Model):
    """
    A review of a product

    Reviews can belong to a user or be anonymous.
    """
    product = models.ForeignKey('catalogue.Product', related_name='reviews', null=True, on_delete=models.CASCADE)
    SCORE_CHOICES = tuple([(x, x) for x in range(0, 6)])
    score = models.SmallIntegerField(_('Score'), choices=SCORE_CHOICES)
    title = models.CharField(verbose_name=pgettext_lazy('Product review title', 'Title'), max_length=255, validators=[validators.non_whitespace])
    body = models.TextField(_('Body'))
    user = models.ForeignKey(AUTH_USER_MODEL, blank=True, null=True, on_delete=models.CASCADE, related_name='reviews')
    name = models.CharField(pgettext_lazy('Anonymous reviewer name', 'Name'), max_length=255, blank=True)
    email = models.EmailField(_('Email'), blank=True)
    homepage = models.URLField(_('URL'), blank=True)
    FOR_MODERATION, APPROVED, REJECTED = (0, 1, 2)
    STATUS_CHOICES = ((FOR_MODERATION, _('Requires moderation')), (APPROVED, _('Approved')), (REJECTED, _('Rejected')))
    status = models.SmallIntegerField(_('Status'), choices=STATUS_CHOICES, default=get_default_review_status)
    code = NullCharField(_('Code'), max_length=255, blank=True, null=True, unique=True)
    total_votes = models.IntegerField(_('Total Votes'), default=0)
    delta_votes = models.IntegerField(_('Delta Votes'), default=0, db_index=True)
    date_created = models.DateTimeField(auto_now_add=True)
    objects = ProductReviewQuerySet.as_manager()

    class Meta:
        abstract = True
        app_label = 'reviews'
        ordering = ['-delta_votes', 'id']
        unique_together = (('product', 'user'),)
        verbose_name = _('Product review')
        verbose_name_plural = _('Product reviews')

    def get_absolute_url(self):
        kwargs = {'product_slug': self.product.slug, 'product_pk': self.product.id, 'pk': self.id}
        return reverse('catalogue:reviews-detail', kwargs=kwargs)

    def __str__(self):
        return self.title

    def clean(self):
        self.title = self.title.strip()
        self.body = self.body.strip()
        if not self.user and (not (self.name and self.email)):
            raise ValidationError(_('Anonymous reviews must include a name and an email'))

    def vote_up(self, user):
        self.votes.create(user=user, delta=AbstractVote.UP)

    def vote_down(self, user):
        self.votes.create(user=user, delta=AbstractVote.DOWN)

    def save(self, *args, **kwargs):
        super().save(*args, **kwargs)
        self.product.update_rating()

    def delete(self, *args, **kwargs):
        super().delete(*args, **kwargs)
        if self.product is not None:
            self.product.update_rating()

    @property
    def is_anonymous(self):
        return self.user is None

    @property
    def pending_moderation(self):
        return self.status == self.FOR_MODERATION

    @property
    def is_approved(self):
        return self.status == self.APPROVED

    @property
    def is_rejected(self):
        return self.status == self.REJECTED

    @property
    def has_votes(self):
        return self.total_votes > 0

    @property
    def num_up_votes(self):
        """Returns the total up votes"""
        return int((self.total_votes + self.delta_votes) / 2)

    @property
    def num_down_votes(self):
        """Returns the total down votes"""
        return int((self.total_votes - self.delta_votes) / 2)

    @property
    def reviewer_name(self):
        if self.user:
            name = self.user.get_full_name()
            return name if name else _('anonymous')
        else:
            return self.name

    def update_totals(self):
        """
        Update total and delta votes
        """
        result = self.votes.aggregate(score=Sum('delta'), total_votes=Count('id'))
        self.total_votes = result['total_votes'] or 0
        self.delta_votes = result['score'] or 0
        self.save()

    def can_user_vote(self, user):
        """
        Test whether the passed user is allowed to vote on this
        review
        """
        if not user.is_authenticated:
            return (False, _('Only signed in users can vote'))
        vote = self.votes.model(review=self, user=user, delta=1)
        try:
            vote.full_clean()
        except ValidationError as e:
            return (False, '%s' % e)
        return (True, '')

class CatalogueReviewsConfig(OscarConfig):
    label = 'reviews'
    name = 'oscar.apps.catalogue.reviews'
    verbose_name = _('Catalogue reviews')
    hidable_feature_name = 'reviews'

    def ready(self):
        self.detail_view = get_class('catalogue.reviews.views', 'ProductReviewDetail')
        self.create_view = get_class('catalogue.reviews.views', 'CreateProductReview')
        self.vote_view = get_class('catalogue.reviews.views', 'AddVoteView')
        self.list_view = get_class('catalogue.reviews.views', 'ProductReviewList')

    def get_urls(self):
        urls = [path('<int:pk>/', self.detail_view.as_view(), name='reviews-detail'), path('add/', self.create_view.as_view(), name='reviews-add'), path('<int:pk>/vote/', login_required(self.vote_view.as_view()), name='reviews-vote'), path('', self.list_view.as_view(), name='reviews-list')]
        return self.post_process_urls(urls)

