class PartnerProductFilterMixin:

    def filter_queryset(self, queryset):
        """
        Restrict the queryset to products the given user has access to.
        A staff user is allowed to access all Products.
        A non-staff user is only allowed access to a product if they are in at
        least one stock record's partner user list.
        """
        user = self.request.user
        if user.is_staff:
            return queryset
        return queryset.filter(Q(children__stockrecords__partner__users__pk=user.pk) | Q(stockrecords__partner__users__pk=user.pk)).distinct()

class PublicVisibilityUpdateMixin(BulkEditMixin):
    actions = ('make_public', 'make_non_public')

    def make_non_public(self, request, records):
        return self._update_public_flag(records, False)

    def make_public(self, request, records):
        return self._update_public_flag(records, True)

    @atomic
    def _update_public_flag(self, records, value):
        for record in records:
            record.is_public = value
            record.save()
        total_records = len(records)
        messages.info(self.request, ngettext('Public status was successfully updated for %(count)d record.', 'Public status was successfully updated for %(count)d records.', total_records) % {'count': total_records})
        return redirect(self.request.get_full_path())

class ProductListView(PublicVisibilityUpdateMixin, PartnerProductFilterMixin, SingleTableView):
    """
    Dashboard view of the product list.
    Supports the permission-based dashboard.
    """
    template_name = 'oscar/dashboard/catalogue/product_list.html'
    model = Product
    form_class = ProductSearchForm
    productclass_form_class = ProductClassSelectForm
    table_class = ProductTable
    context_table_name = 'products'

    def get_context_data(self, **kwargs):
        ctx = super().get_context_data(**kwargs)
        ctx['form'] = self.form
        ctx['productclass_form'] = self.productclass_form_class()
        ctx['has_products'] = self.get_queryset().exists()
        return ctx

    def get_description(self, form):
        if form.is_valid() and any(form.cleaned_data.values()):
            return _('Product search results')
        return _('Products')

    def get_table(self, **kwargs):
        if 'recently_edited' in self.request.GET:
            kwargs.update(dict(orderable=False))
        table = super().get_table(**kwargs)
        table.caption = self.get_description(self.form)
        return table

    def get_table_pagination(self, table):
        return dict(per_page=settings.OSCAR_DASHBOARD_ITEMS_PER_PAGE)

    def get_queryset(self):
        """
        Build the queryset for this list
        """
        queryset = Product.objects.browsable_dashboard().base_queryset()
        queryset = self.filter_queryset(queryset)
        queryset = self.apply_search(queryset)
        return queryset

    def apply_search(self, queryset):
        """
        Search through the filtered queryset.

        We must make sure that we don't return search results that the user is not allowed
        to see (see filter_queryset).
        """
        self.form = self.form_class(self.request.GET)
        if not self.form.is_valid():
            return queryset
        data = self.form.cleaned_data
        upc = data.get('upc')
        if upc:
            matches_upc = Product.objects.filter(Q(upc__iexact=upc) | Q(children__upc__iexact=upc))
            qs_match = queryset.filter(Q(id__in=matches_upc.values('id')) | Q(id__in=matches_upc.values('parent_id')))
            if qs_match.exists():
                queryset = qs_match
            else:
                matches_upc = Product.objects.filter(Q(upc__icontains=upc) | Q(children__upc__icontains=upc))
                queryset = queryset.filter(Q(id__in=matches_upc.values('id')) | Q(id__in=matches_upc.values('parent_id')))
        title = data.get('title')
        if title:
            queryset = queryset.filter(Q(title__icontains=title) | Q(children__title__icontains=title))
        return queryset.distinct()

