class Command(BaseCommand):
    help = 'Finds email addresses that are used by more than one user. Casing is ignored.'

    def handle(self, *args, **options):
        emails = User.objects.values_list('email', flat=True)
        emails = map(lambda x: x.lower(), emails)
        duplicates = sorted([(email, count) for email, count in Counter(emails).most_common() if count > 1])
        if duplicates:
            for email, __ in duplicates:
                users = User.objects.filter(email__iexact=email)
                user_strings = ['{} (#{})'.format(user.get_username(), user.pk) for user in users]
                print('{email} is assigned to: {pk_list}'.format(email=email, pk_list=', '.join(user_strings)))
        else:
            print('No duplicate email addresses found!')

class Command(BaseCommand):
    """
    Copy Oscar's statics into local project so they can be used as a base for
    styling a new site.
    """
    help = "Copy Oscar's static files"

    def add_arguments(self, parser):
        parser.add_argument('target_path', nargs='?', default='static', help='Directory path (relative to current working directory, or absolute) in local project, to copy files to. This directory should be included in STATICFILES_DIRS, in order for your local overrides to be picked up.')

    def handle(self, *args, **options):
        folder = options['target_path']
        if not folder.startswith('/'):
            destination = os.path.join(os.getcwd(), folder)
        else:
            destination = folder
        if os.path.exists(destination):
            raise CommandError('The folder %s already exists - aborting!' % destination)
        source = os.path.realpath(os.path.join(os.path.dirname(__file__), '../../static'))
        self.stdout.write("Copying Oscar's static files to %s" % destination)
        shutil.copytree(source, destination)
        if destination not in settings.STATICFILES_DIRS:
            self.stdout.write('You need to add %s to STATICFILES_DIRS in order for your local overrides to be picked up' % destination)

