class TestCategoryTemplateTags(TestCase):

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.template = '\n          {% if tree_categories %}\n              <ul>\n              {% for tree_category, info in tree_categories %}\n                  <li>\n                  {% if tree_category.pk == category.pk %}\n                      <strong>{{ tree_category.name }}</strong>\n                  {% else %}\n                      <a href="{{ tree_category.get_absolute_url }}">\n                          {{ tree_category.name }}</a>\n                  {% endif %}\n                  {% if info.has_children %}<ul>{% else %}</li>{% endif %}\n                  {% for n in info.num_to_close %}\n                      </ul></li>\n                  {% endfor %}\n              {% endfor %}\n              </ul>\n          {% endif %}\n        '

    def setUp(self):
        breadcrumbs = ('Books > Fiction > Horror > Teen', 'Books > Fiction > Horror > Gothic', 'Books > Fiction > Comedy', 'Books > Non-fiction > Biography', 'Books > Non-fiction > Programming', 'Books > Children')
        for trail in breadcrumbs:
            create_from_breadcrumbs(trail)

    def test_category_extra_info(self):
        annotated_list = get_annotated_list(depth=3)
        expected_categories_info = {'Books': {'has_children': True, 'len_num_to_close': 0}, 'Fiction': {'has_children': True, 'len_num_to_close': 0}, 'Horror': {'has_children': False, 'len_num_to_close': 0}, 'Comedy': {'has_children': False, 'len_num_to_close': 1}, 'Non-fiction': {'has_children': True, 'len_num_to_close': 0}, 'Biography': {'has_children': False, 'len_num_to_close': 0}, 'Programming': {'has_children': False, 'len_num_to_close': 1}, 'Children': {'has_children': False, 'len_num_to_close': 1}}
        actual_categories_info = {category.name: {'has_children': category.get('has_children', False), 'len_num_to_close': len(category['num_to_close'])} for category, _ in annotated_list}
        self.assertEqual(json.dumps(expected_categories_info), json.dumps(actual_categories_info))

    def get_category_names(self, depth=None, parent=None):
        """
        For the tests, we are only interested in the category names returned
        from the template tag. This helper calls the template tag and
        returns a list of the included categories.
        """
        annotated_list = get_annotated_list(depth, parent)
        names = [category.name for category, __ in annotated_list]
        names_set = set(names)
        self.assertEqual(len(names_set), len(names))
        return names_set

    def test_all_categories(self):
        expected_categories = {'Books', 'Fiction', 'Horror', 'Teen', 'Gothic', 'Comedy', 'Non-fiction', 'Biography', 'Programming', 'Children'}
        actual_categories = self.get_category_names()
        self.assertEqual(expected_categories, actual_categories)

    def test_categories_depth(self):
        expected_categories = {'Books'}
        actual_categories = self.get_category_names(depth=1)
        self.assertEqual(expected_categories, actual_categories)

    def test_categories_parent(self):
        parent = Category.objects.get(name='Fiction')
        actual_categories = self.get_category_names(parent=parent)
        expected_categories = {'Horror', 'Teen', 'Gothic', 'Comedy'}
        self.assertEqual(expected_categories, actual_categories)

    def test_categories_depth_parent(self):
        parent = Category.objects.get(name='Fiction')
        actual_categories = self.get_category_names(depth=1, parent=parent)
        expected_categories = {'Horror', 'Comedy'}
        self.assertEqual(expected_categories, actual_categories)

