class TestDeprecatedDecorator(TestCase):

    def test_decorate_function(self):

        @deprecated
        def func():
            return True
        with warnings.catch_warnings(record=True) as caught:
            warnings.simplefilter('always')
            self.assertTrue(func())
            assert len(caught) == 1
            assert issubclass(caught[0].category, DeprecationWarning)

    def test_decorate_class(self):

        class Cls(object):
            val = False

            def __init__(self):
                self.val = True
        Deprecated = deprecated(Cls)
        with warnings.catch_warnings(record=True) as caught:
            warnings.simplefilter('always')
            obj = Deprecated()
            self.assertTrue(obj.val)
            assert len(caught) == 1
            assert issubclass(caught[0].category, DeprecationWarning)

    def test_subclass_decorated(self):

        class Cls(object):
            val = False

            def __init__(self):
                self.val = True
        Deprecated = deprecated(Cls)

        class SubCls(Deprecated):
            pass
        with warnings.catch_warnings(record=True) as caught:
            warnings.simplefilter('always')
            obj = SubCls()
            self.assertTrue(obj.val)
            assert len(caught) == 1
            assert issubclass(caught[0].category, DeprecationWarning)

