class ProductQuerysetPrefetchTestCase(TestCase):

    def test_get_public_children_prefetch(self):
        for _ in range(10):
            parent = ProductFactory(structure='parent', stockrecords=[])
            for _ in range(10):
                ProductFactory(structure='child', parent=parent, stockrecords=[])
        with self.assertNumQueries(11):
            parents = Product.objects.filter(structure='parent')
            for parent in parents:
                list(parent.get_public_children())
        with self.assertNumQueries(2):
            parents = Product.objects.filter(structure='parent').prefetch_public_children()
            for parent in parents:
                list(parent.get_public_children())

    def test_get_browsable_categories_prefetch(self):
        for _ in range(10):
            parent = ProductFactory(structure='parent', stockrecords=[])
            for _ in range(10):
                ProductFactory(structure='child', parent=parent, stockrecords=[])
        with self.assertNumQueries(211):
            products = Product.objects.all()
            for product in products:
                list(product.get_categories())
        with self.assertNumQueries(4):
            products = Product.objects.prefetch_browsable_categories()
            for product in products:
                list(product.get_categories())

    def test_get_attribute_values_prefetch(self):
        for _ in range(5):
            parent = ProductFactory(structure='parent', stockrecords=[])
            for _ in range(3):
                ProductAttributeValueFactory(product=parent)
            for _ in range(5):
                child = ProductFactory(structure='child', parent=parent, stockrecords=[])
                for _ in range(3):
                    ProductAttributeValueFactory(product=child)
        with self.assertNumQueries(56):
            products = Product.objects.all()
            for product in products:
                list(product.get_attribute_values())
        with self.assertNumQueries(7):
            products = Product.objects.prefetch_attribute_values()
            for product in products:
                list(product.get_attribute_values())
        prefetched_products = list(Product.objects.prefetch_attribute_values())
        for product in prefetched_products:
            if product.is_child:
                child_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
                parent_attr_codes = set((av.attribute.code for av in product.parent.attribute_values.all()))
                prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
                self.assertEqual(prefetched_attr_codes, child_attr_codes.union(parent_attr_codes))
            else:
                own_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
                prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
                self.assertEqual(prefetched_attr_codes, own_attr_codes)

    def test_get_attribute_values_prefetch_including_child_attributes(self):
        for _ in range(5):
            parent = ProductFactory(structure='parent', stockrecords=[])
            for _ in range(3):
                ProductAttributeValueFactory(product=parent)
            for _ in range(5):
                child = ProductFactory(structure='child', parent=parent, stockrecords=[])
                for _ in range(3):
                    ProductAttributeValueFactory(product=child)
        with self.assertNumQueries(86):
            products = Product.objects.all()
            for product in products:
                list(product.get_attribute_values())
                if product.is_parent:
                    for child in product.children.all():
                        list(child.get_attribute_values())
        with self.assertNumQueries(37):
            products = Product.objects.prefetch_attribute_values()
            for product in products:
                list(product.get_attribute_values())
                if product.is_parent:
                    for child in product.children.all():
                        list(child.get_attribute_values())
        with self.assertNumQueries(12):
            products = Product.objects.prefetch_attribute_values(include_parent_children_attributes=True)
            for product in products:
                list(product.get_attribute_values())
                if product.is_parent:
                    for child in product.children.all():
                        list(child.get_attribute_values())
        prefetched_products = list(Product.objects.prefetch_attribute_values(include_parent_children_attributes=True))
        for product in prefetched_products:
            if product.is_child:
                child_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
                parent_attr_codes = set((av.attribute.code for av in product.parent.attribute_values.all()))
                prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
                self.assertEqual(prefetched_attr_codes, child_attr_codes.union(parent_attr_codes))
                self.assertEqual(prefetched_attr_codes, child_attr_codes.union(parent_attr_codes))
            else:
                own_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
                prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
                self.assertEqual(prefetched_attr_codes, own_attr_codes)
                if product.is_parent:
                    for child in product.children.all():
                        child_attr_codes = set((av.attribute.code for av in child.attribute_values.all()))
                        combined_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
                        self.assertEqual(combined_attr_codes, own_attr_codes.union(child_attr_codes))

    def test_get_attribute_values_prefetch_specific_child_behavior(self):
        parent = ProductFactory(structure='parent', stockrecords=[])
        attr1 = ProductAttributeFactory(name='attr1', code='attr1', type='text')
        attr2 = ProductAttributeFactory(name='attr2', code='attr2', type='text')
        attr3 = ProductAttributeFactory(name='attr3', code='attr3', type='text')
        ProductAttributeValueFactory(product=parent, attribute=attr1, value_text='parent_attr1')
        ProductAttributeValueFactory(product=parent, attribute=attr2, value_text='parent_attr2')
        ProductAttributeValueFactory(product=parent, attribute=attr3, value_text='parent_attr3')
        child1 = ProductFactory(structure='child', parent=parent, stockrecords=[])
        child2 = ProductFactory(structure='child', parent=parent, stockrecords=[])
        child3 = ProductFactory(structure='child', parent=parent, stockrecords=[])
        ProductAttributeValueFactory(product=child1, attribute=attr1, value_text='child1_attr1')
        ProductAttributeValueFactory(product=child2, attribute=attr2, value_text='child2_attr2')
        ProductAttributeValueFactory(product=child3, attribute=attr3, value_text='child3_attr3')
        prefetched_products = Product.objects.prefetch_attribute_values()
        parent = next((p for p in prefetched_products if p.id == parent.id))
        prefetched_child1 = next((p for p in prefetched_products if p.id == child1.id))
        prefetched_child2 = next((p for p in prefetched_products if p.id == child2.id))
        prefetched_child3 = next((p for p in prefetched_products if p.id == child3.id))
        child1_attr_values = {av.attribute.code: av.value_text for av in prefetched_child1.get_attribute_values()}
