        child2_attr_values = {av.attribute.code: av.value_text for av in prefetched_child2.get_attribute_values()}
        print('child2_attr_values: ', child2_attr_values, '\n')
        self.assertEqual(child2_attr_values['attr1'], 'parent_attr1')
